{
  "name": "SonicPulse AI - Audio Feature Recommender",
  "description": "An advanced music recommendation engine that uses objective signal processing features (MFCCs, Spectral Centroid, ZCR) to cluster and suggest tracks based on timbre, rhythm, and harmony without relying on metadata tags.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AudioFeatures {
  mfccs: number; // Timbral texture (0-100)
  spectralCentroid: number; // Brightness (0-100)
  zcr: number; // Timbre roughness/percussion (0-100)
  chroma: number; // Harmonic complexity (0-100)
  tempo: number; // BPM (60-180)
  energy: number; // Overall intensity (0-100)
}

export interface Song {
  id: string;
  title: string;
  artist: string;
  genre: string;
  features: AudioFeatures;
  embedding: [number, number]; // 2D projection for visualization
  clusterId: number;
}

export interface UserProfile {
  preferenceVector: AudioFeatures;
  history: string[]; // Song IDs
  liked: string[]; // Song IDs
}

export interface Recommendation {
  song: Song;
  similarity: number;
  explanation: string;
}

import { GoogleGenAI } from "@google/genai";
import { AudioFeatures, Song } from "../types";

export const getMusicalExplanation = async (song: Song, userPref: AudioFeatures): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Acts as a musicology AI. Explain why a song is recommended to a user based on signal processing features.

    Target Song: "${song.title}" by ${song.artist}
    Song Features:
    - Timbre Texture (MFCCs): ${song.features.mfccs}/100
    - Brightness (Spectral Centroid): ${song.features.spectralCentroid}/100
    - Roughness (ZCR): ${song.features.zcr}/100
    - Harmony (Chroma): ${song.features.chroma}/100
    - Rhythm (Tempo): ${song.features.tempo} BPM
    - Intensity (Energy): ${song.features.energy}/100

    User Preference Profile:
    - Preferred Timbre: ${userPref.mfccs}/100
    - Preferred Brightness: ${userPref.spectralCentroid}/100
    - Preferred Harmony: ${userPref.chroma}/100
    - Preferred Energy: ${userPref.energy}/100

    Write a concise 2-sentence explanation highlighting the specific signal properties that match the user's taste. Avoid generic praise; mention things like "timbral richness", "high-frequency spectral energy", or "harmonic complexity".
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.0-flash-exp', // Fast model for real-time UI
      contents: prompt,
    });
    return response.text || "Recommended based on similar acoustic properties and timbral consistency.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "This track aligns with your preference for specific timbral textures and rhythmic patterns.";
  }
};

import React from 'react';
import {
  Radar, RadarChart, PolarGrid, PolarAngleAxis, ResponsiveContainer
} from 'recharts';
import { AudioFeatures } from '../types';

interface FeatureRadarProps {
  features: AudioFeatures;
  name?: string;
  color?: string;
}

const FeatureRadar: React.FC<FeatureRadarProps> = ({ features, name = "Song", color = "#3b82f6" }) => {
  const data = [
    { subject: 'Timbre (MFCC)', A: features.mfccs, fullMark: 100 },
    { subject: 'Brightness', A: features.spectralCentroid, fullMark: 100 },
    { subject: 'Roughness', A: features.zcr, fullMark: 100 },
    { subject: 'Harmony', A: features.chroma, fullMark: 100 },
    { subject: 'Intensity', A: features.energy, fullMark: 100 },
  ];

  return (
    <div className="w-full h-64">
      <ResponsiveContainer width="100%" height="100%">
        <RadarChart cx="50%" cy="50%" outerRadius="70%" data={data}>
          <PolarGrid stroke="#4b5563" />
          <PolarAngleAxis dataKey="subject" tick={{ fill: '#9ca3af', fontSize: 10 }} />
          <Radar
            name={name}
            dataKey="A"
            stroke={color}
            fill={color}
            fillOpacity={0.6}
          />
        </RadarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default FeatureRadar;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Song } from '../types';

interface EmbeddingMapProps {
  songs: Song[];
  selectedSongId?: string;
  onSelectSong: (song: Song) => void;
}

const EmbeddingMap: React.FC<EmbeddingMapProps> = ({ songs, selectedSongId, onSelectSong }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const margin = { top: 20, right: 20, bottom: 20, left: 20 };
    const width = 400 - margin.left - margin.right;
    const height = 400 - margin.top - margin.bottom;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const g = svg.append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const x = d3.scaleLinear().domain([-1.2, 1.2]).range([0, width]);
    const y = d3.scaleLinear().domain([-1.2, 1.2]).range([height, 0]);

    const colorScale = d3.scaleOrdinal(d3.schemeCategory10);

    // Grid lines
    g.append("g")
      .attr("class", "grid")
      .attr("stroke", "#1f2937")
      .attr("stroke-opacity", 0.5)
      .call(d3.axisBottom(x).ticks(5).tickSize(height).tickFormat(() => ""));

    g.append("g")
      .attr("class", "grid")
      .attr("stroke", "#1f2937")
      .attr("stroke-opacity", 0.5)
      .call(d3.axisLeft(y).ticks(5).tickSize(-width).tickFormat(() => ""));

    // Plot points
    g.selectAll("circle")
      .data(songs)
      .enter()
      .append("circle")
      .attr("cx", d => x(d.embedding[0]))
      .attr("cy", d => y(d.embedding[1]))
      .attr("r", d => d.id === selectedSongId ? 8 : 5)
      .attr("fill", d => colorScale(d.clusterId.toString()))
      .attr("stroke", d => d.id === selectedSongId ? "#fff" : "none")
      .attr("stroke-width", 2)
      .attr("class", "cursor-pointer transition-all hover:r-10")
      .on("click", (event, d) => onSelectSong(d));

    // Axis labels
    g.append("text")
      .attr("x", width / 2)
      .attr("y", height + 15)
      .attr("text-anchor", "middle")
      .attr("fill", "#6b7280")
      .style("font-size", "10px")
      .text("Latent Dimension 1 (Timbre)");

    g.append("text")
      .attr("transform", "rotate(-90)")
      .attr("x", -height / 2)
      .attr("y", -10)
      .attr("text-anchor", "middle")
      .attr("fill", "#6b7280")
      .style("font-size", "10px")
      .text("Latent Dimension 2 (Rhythm)");

  }, [songs, selectedSongId, onSelectSong]);

  return (
    <div className="bg-gray-900 rounded-xl p-4 shadow-inner border border-gray-800">
      <h3 className="text-sm font-semibold mb-4 text-gray-400 uppercase tracking-wider">Song Embedding Space</h3>
      <svg ref={svgRef} width="100%" height="400" viewBox="0 0 400 400" className="mx-auto" />
      <div className="mt-4 flex flex-wrap gap-2 text-[10px] text-gray-500">
        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-blue-500"></div> Electronic</span>
        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-orange-500"></div> Folk/Jazz</span>
        <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-green-500"></div> Heavy Bass</span>
      </div>
    </div>
  );
};

export default EmbeddingMap;

import React, { useState, useEffect, useCallback } from 'react';
import { MOCK_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures } from './types';
import FeatureRadar from './components/FeatureRadar';
import EmbeddingMap from './components/EmbeddingMap';
import { getMusicalExplanation } from './services/geminiService';

const App: React.FC = () => {
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loading, setLoading] = useState(false);
  const [explaining, setExplaining] = useState<string | null>(null);

  // Calculate similarity between two feature vectors
  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    // Add tempo similarity (normalized)
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures) => {
    setLoading(true);
    const sorted = [...library]
      .map(song => ({
        song,
        similarity: calculateSimilarity(song.features, currentPref),
        explanation: 'Calculating...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 3);

    // Get AI explanations for top 3
    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);
  }, [library]);

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);

    // Update user profile (incremental learning)
    // alpha = 0.2 means the profile moves 20% towards the new song
    const alpha = 0.2;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);

      // Update recommendations based on new vector
      updateRecommendations(newPref);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  useEffect(() => {
    updateRecommendations(userProfile.preferenceVector);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="flex flex-col min-h-screen bg-black">
      {/* Header */}
      <header className="border-b border-gray-800 bg-gray-950/50 backdrop-blur-md sticky top-0 z-10 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center">
            <i className="fas fa-wave-square text-white text-xl"></i>
          </div>
          <div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent">SonicPulse AI</h1>
            <p className="text-[10px] text-gray-500 uppercase tracking-widest font-semibold">Signal-Based Recommendation Engine</p>
          </div>
        </div>
        <div className="flex gap-4">
          <button className="px-4 py-2 bg-gray-900 border border-gray-800 rounded-full text-sm hover:bg-gray-800 transition-colors">
            <i className="fas fa-upload mr-2"></i> Upload Audio
          </button>
        </div>
      </header>

      <main className="flex-1 grid grid-cols-1 lg:grid-cols-12 gap-6 p-6 overflow-hidden">

        {/* Left Panel: Explorer */}
        <div className="lg:col-span-3 space-y-6 overflow-y-auto pr-2 custom-scrollbar">
          <section className="bg-gray-900/40 rounded-2xl p-4 border border-gray-800/50">
            <h2 className="text-xs font-bold text-gray-500 uppercase mb-4 tracking-tighter">Current Session Profile</h2>
            <FeatureRadar features={userProfile.preferenceVector} name="User Profile" color="#6366f1" />
            <div className="mt-4 grid grid-cols-2 gap-2 text-[10px] text-gray-400">
              <div className="bg-gray-800/50 p-2 rounded">
                <p className="opacity-50">AVG TEMPO</p>
                <p className="text-lg font-bold text-white">{userProfile.preferenceVector.tempo} <span className="text-[10px] font-normal">BPM</span></p>
              </div>
              <div className="bg-gray-800/50 p-2 rounded">
                <p className="opacity-50">ENERGY LEVEL</p>
                <p className="text-lg font-bold text-white">{userProfile.preferenceVector.energy}%</p>
              </div>
            </div>
          </section>

          <section>
            <h2 className="text-xs font-bold text-gray-500 uppercase mb-4 px-2">Recent Listens</h2>
            <div className="space-y-2">
              {userProfile.history.map(id => {
                const song = library.find(s => s.id === id);
                if (!song) return null;
                return (
                  <div key={id} className="flex items-center gap-3 p-2 bg-gray-900/50 rounded-lg hover:bg-gray-800 transition-colors cursor-pointer group">
                    <div className="w-10 h-10 bg-gray-800 rounded flex items-center justify-center text-xs text-gray-500 group-hover:text-blue-400">
                      <i className="fas fa-play"></i>
                    </div>
                    <div>
                      <p className="text-sm font-medium">{song.title}</p>
                      <p className="text-xs text-gray-500">{song.artist}</p>
                    </div>
                  </div>
                );
              })}
            </div>
          </section>
        </div>

        {/* Center Panel: Map & Library */}
        <div className="lg:col-span-6 space-y-6 flex flex-col h-full overflow-hidden">
          <div className="flex-none">
            <EmbeddingMap 
              songs={library} 
              selectedSongId={selectedSong?.id} 
              onSelectSong={handleSelectSong} 
            />
          </div>

          <div className="flex-1 min-h-0 bg-gray-900/20 rounded-2xl border border-gray-800/50 p-6 overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold">Signal Library</h2>
              <div className="flex gap-2 text-xs">
                <span className="px-3 py-1 bg-blue-500/10 text-blue-400 border border-blue-500/20 rounded-full">All Samples</span>
                <span className="px-3 py-1 bg-gray-800 text-gray-400 rounded-full">High MFCC</span>
                <span className="px-3 py-1 bg-gray-800 text-gray-400 rounded-full">Fast Tempo</span>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {library.map(song => (
                <div 
                  key={song.id}
                  onClick={() => handleSelectSong(song)}
                  className={`p-4 rounded-xl border transition-all cursor-pointer ${
                    selectedSong?.id === song.id 
                    ? 'bg-blue-600/10 border-blue-500/50 ring-1 ring-blue-500/20' 
                    : 'bg-gray-900/40 border-gray-800 hover:border-gray-700'
                  }`}
                >
                  <div className="flex justify-between items-start mb-3">
                    <div>
                      <h3 className="font-bold text-white">{song.title}</h3>
                      <p className="text-xs text-gray-400">{song.artist} • {song.genre}</p>
                    </div>
                    <div className="text-[10px] font-mono text-gray-500">#{song.id.padStart(4, '0')}</div>
                  </div>
                  <div className="space-y-2">
                    <div className="h-1 bg-gray-800 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500" style={{ width: `${song.features.energy}%` }}></div>
                    </div>
                    <div className="flex justify-between text-[10px] text-gray-500">
                      <span>Timbre: {song.features.mfccs}</span>
                      <span>{song.features.tempo} BPM</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Right Panel: Recommendations & AI Explainability */}
        <div className="lg:col-span-3 space-y-6 overflow-y-auto pl-2 custom-scrollbar">
          <section className="bg-indigo-600/5 rounded-2xl border border-indigo-500/20 p-5">
            <div className="flex items-center gap-2 mb-4">
              <i className="fas fa-microchip text-indigo-400"></i>
              <h2 className="text-sm font-bold uppercase tracking-widest text-indigo-200">AI Signal Matches</h2>
            </div>

            {loading ? (
              <div className="flex flex-col items-center justify-center py-12 space-y-4">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
                <p className="text-xs text-gray-500 animate-pulse">Analyzing vector proximity...</p>
              </div>
            ) : (
              <div className="space-y-6">
                {recommendations.map((rec, idx) => (
                  <div key={rec.song.id} className="group">
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2">
                        <span className="text-indigo-500 font-mono text-xs">0{idx + 1}</span>
                        <h3 className="font-bold text-sm text-gray-100 group-hover:text-indigo-400 transition-colors">{rec.song.title}</h3>
                      </div>
                      <span className="text-[10px] px-2 py-0.5 bg-green-500/10 text-green-400 rounded border border-green-500/20">
                        {Math.round(rec.similarity * 1000) / 10}% match
                      </span>
                    </div>

                    <div className="relative pl-6 border-l border-gray-800 ml-1 py-1">
                      <p className="text-[11px] leading-relaxed text-gray-400 italic">
                        "{rec.explanation}"
                      </p>
                      <div className="absolute -left-1 top-0 w-2 h-2 rounded-full bg-gray-800"></div>
                    </div>

                    <button 
                      onClick={() => handleSelectSong(rec.song)}
                      className="mt-3 w-full py-1.5 bg-gray-900 border border-gray-800 text-[11px] font-bold rounded-lg hover:bg-gray-800 transition-all opacity-0 group-hover:opacity-100"
                    >
                      EXPLORE SIGNAL
                    </button>
                  </div>
                ))}
              </div>
            )}
          </section>

          {/* Feature Breakdown Explainer */}
          {selectedSong && (
            <section className="bg-gray-900/40 rounded-2xl p-4 border border-gray-800/50">
              <h3 className="text-xs font-bold text-gray-500 uppercase mb-4 tracking-tighter">Feature Breakdown: {selectedSong.title}</h3>
              <div className="space-y-4">
                {[
                  { label: 'Timbral Texture (MFCC)', val: selectedSong.features.mfccs, desc: 'Describes the richness and color of the instruments.' },
                  { label: 'Brightness (Spectral)', val: selectedSong.features.spectralCentroid, desc: 'Indicates presence of high-frequency content.' },
                  { label: 'Roughness (ZCR)', val: selectedSong.features.zcr, desc: 'Measures percussive noise and signal variability.' },
                ].map(f => (
                  <div key={f.label} className="group">
                    <div className="flex justify-between text-[11px] mb-1">
                      <span className="text-gray-300">{f.label}</span>
                      <span className="font-mono text-blue-400">{f.val}%</span>
                    </div>
                    <div className="h-1.5 bg-gray-800 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500/50 transition-all duration-1000" style={{ width: `${f.val}%` }}></div>
                    </div>
                    <p className="text-[9px] text-gray-600 mt-1 opacity-0 group-hover:opacity-100 transition-opacity">{f.desc}</p>
                  </div>
                ))}
              </div>
            </section>
          )}
        </div>
      </main>

      {/* Persistent Audio Controller Simulation */}
      <footer className="h-20 bg-gray-950 border-t border-gray-800 px-6 flex items-center justify-between">
        <div className="flex items-center gap-4 w-1/4">
          {selectedSong ? (
            <>
              <div className="w-12 h-12 bg-gradient-to-br from-indigo-500 to-blue-600 rounded-md flex items-center justify-center shadow-lg">
                <i className="fas fa-music text-white"></i>
              </div>
              <div className="min-w-0">
                <p className="text-sm font-bold truncate">{selectedSong.title}</p>
                <p className="text-xs text-gray-500 truncate">{selectedSong.artist}</p>
              </div>
            </>
          ) : (
            <div className="text-xs text-gray-600 italic">Select a song to analyze signal...</div>
          )}
        </div>

        <div className="flex flex-col items-center gap-2 w-1/2">
          <div className="flex items-center gap-6">
            <button className="text-gray-500 hover:text-white transition-colors"><i className="fas fa-random text-sm"></i></button>
            <button className="text-gray-500 hover:text-white transition-colors"><i className="fas fa-step-backward text-lg"></i></button>
            <button className="w-10 h-10 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform">
              <i className="fas fa-play ml-0.5"></i>
            </button>
            <button className="text-gray-500 hover:text-white transition-colors"><i className="fas fa-step-forward text-lg"></i></button>
            <button className="text-gray-500 hover:text-white transition-colors"><i className="fas fa-redo text-sm"></i></button>
          </div>
          <div className="w-full flex items-center gap-2 px-10">
            <span className="text-[10px] text-gray-500">0:42</span>
            <div className="flex-1 h-1 bg-gray-800 rounded-full cursor-pointer group">
              <div className="h-full bg-white rounded-full relative" style={{ width: '35%' }}>
                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
              </div>
            </div>
            <span className="text-[10px] text-gray-500">3:30</span>
          </div>
        </div>

        <div className="flex items-center justify-end gap-4 w-1/4">
          <i className="fas fa-list-ul text-xs text-gray-500 hover:text-white cursor-pointer"></i>
