import React, { useState, useEffect, useCallback } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation } from './services/geminiService';

const App: React.FC = () => {
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [spotifyConnected, setSpotifyConnected] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loading, setLoading] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures) => {
    setLoading(true);
    // Use the current library (which will be the imported one after login)
    const sorted = [...(spotifyConnected ? IMPORTED_USER_LIBRARY : library)]
      .map(song => ({
        song,
        similarity: calculateSimilarity(song.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 3);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);
  }, [library, spotifyConnected]);

  const handleSpotifyLogin = () => {
    setIsLoggingIn(true);
    // Simulated Popup Authentication
    setTimeout(() => {
      setIsLoggingIn(false);
      setIsImporting(true);

      // Simulate multi-stage import
      const steps = [
        { progress: 20, msg: 'Connecting to Spotify API...' },
        { progress: 45, msg: 'Fetching "Liked Songs" (428 tracks)...' },
        { progress: 70, msg: 'Analyzing timbral clusters...' },
        { progress: 95, msg: 'Generating latent sound map...' },
      ];

      steps.forEach((step, i) => {
        setTimeout(() => {
          setImportProgress(step.progress);
          setImportStatus(step.msg);
          if (i === steps.length - 1) {
            setTimeout(() => {
              setLibrary(IMPORTED_USER_LIBRARY);
              setSpotifyConnected(true);
              setIsImporting(false);
              handleSelectSong(IMPORTED_USER_LIBRARY[0]);
            }, 1000);
          }
        }, (i + 1) * 800);
      });
    }, 1200);
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    setShowFeedback(true);

    const alpha = 0.3;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const submitFeedback = (satisfied: boolean) => {
    setShowFeedback(false);
    if (!satisfied) {
      const jitteredPref = { ...userProfile.preferenceVector };
      jitteredPref.energy = Math.max(0, Math.min(100, jitteredPref.energy + (Math.random() - 0.5) * 30));
      updateRecommendations(jitteredPref);
    }
  };

  if (!spotifyConnected && !isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-b from-indigo-900/30 to-black pointer-events-none"></div>
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-20 pointer-events-none"></div>

        <div className="relative z-10 flex flex-col items-center max-w-md w-full">
          <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center mb-10 shadow-[0_0_50px_rgba(255,255,255,0.1)] transform hover:rotate-6 transition-transform">
            <i className="fas fa-wave-square text-black text-5xl"></i>
          </div>
          <h1 className="text-5xl font-black text-white mb-3 tracking-tighter italic">Musologist</h1>
          <p className="text-gray-400 text-center mb-12 font-medium leading-relaxed">
            Stop searching by genre. Start discovering by <span className="text-indigo-400">sound</span>. 
            Connect your library to map your sonic identity.
          </p>

          <button 
            onClick={handleSpotifyLogin}
            disabled={isLoggingIn}
            className="group w-full py-5 bg-[#1DB954] hover:bg-[#1ed760] text-black font-black rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.02] active:scale-[0.98] shadow-2xl shadow-green-500/20"
          >
            {isLoggingIn ? (
              <div className="w-6 h-6 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
            ) : (
              <>
                <i className="fab fa-spotify text-3xl group-hover:rotate-12 transition-transform"></i>
                Sign in with Spotify
              </>
            )}
          </button>

          <div className="mt-10 flex items-center gap-6 text-gray-600">
             <div className="flex flex-col items-center">
                <span className="text-xl font-bold text-gray-400">10k+</span>
                <span className="text-[10px] uppercase font-black tracking-widest">Signal Nodes</span>
             </div>
             <div className="w-px h-8 bg-white/10"></div>
             <div className="flex flex-col items-center">
                <span className="text-xl font-bold text-gray-400">99%</span>
                <span className="text-[10px] uppercase font-black tracking-widest">Sync Accuracy</span>
             </div>
          </div>
        </div>
      </div>
    );
  }

  if (isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6">
        <div className="relative">
          <SonicOrb energy={70} brightness={80} intensity={50} />
          <div className="absolute inset-0 flex items-center justify-center">
             <span className="text-3xl font-black text-white">{importProgress}%</span>
          </div>
        </div>
        <h2 className="text-2xl font-black text-white mt-12 mb-3 tracking-tight">Extracting Sonic Patterns</h2>
        <p className="text-gray-500 text-sm font-medium h-6">{importStatus}</p>

        <div className="w-64 h-1.5 bg-white/5 rounded-full mt-10 overflow-hidden">
           <div className="h-full bg-indigo-500 transition-all duration-500" style={{ width: `${importProgress}%` }}></div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">

      {/* Sidebar (Spotify-like) */}
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5">
        <div className="flex items-center gap-3 px-2">
          <i className="fas fa-wave-square text-white text-xl"></i>
          <span className="text-lg font-black tracking-tight italic">Musologist</span>
        </div>

        <div className="space-y-4 px-2">
          <div className="flex items-center gap-4 text-gray-400 hover:text-white cursor-pointer transition-colors group">
            <i className="fas fa-home text-lg"></i>
            <span className="text-sm font-bold">Home</span>
          </div>
          <div className="flex items-center gap-4 text-gray-400 hover:text-white cursor-pointer transition-colors group">
