export interface AudioFeatures {
  mfccs: number; // Timbral texture (0-100)
  spectralCentroid: number; // Brightness (0-100)
  zcr: number; // Timbre roughness/percussion (0-100)
  chroma: number; // Harmonic complexity (0-100)
  tempo: number; // BPM (60-180)
  energy: number; // Overall intensity (0-100)
}

export interface Song {
  id: string;
  title: string;
  artist: string;
  genre: string;
  features: AudioFeatures;
  embedding: [number, number]; // 2D projection for visualization
  clusterId: number;
}

export interface UserProfile {
  preferenceVector: AudioFeatures;
  history: string[]; // Song IDs
  liked: string[]; // Song IDs
}

export interface Recommendation {
  song: Song;
  similarity: number;
  explanation: string;
}

export interface SearchSource {
  title: string;
  uri: string;
}

export interface LiveDiscovery {
  text: string;
  sources: SearchSource[];
}

import { GoogleGenAI } from "@google/genai";
import { AudioFeatures, Song, LiveDiscovery, SearchSource } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMusicalExplanation = async (song: Song, userPref: AudioFeatures): Promise<string> => {
  const prompt = `
    Acts as a intuitive music discovery AI. Explain why a song matches a user's current "vibe" based on underlying acoustic patterns.

    CRITICAL: DO NOT mention technical terms like MFCC, Spectral Centroid, ZCR, or Chroma. 
    The user should not know about these metrics.

    Target Song: "${song.title}" by ${song.artist}
    Acoustic Profile:
    - Vibe: ${song.features.energy > 70 ? 'High Energy' : 'Chilled'}
    - Texture: ${song.features.mfccs > 60 ? 'Rich and Layered' : 'Clean and Minimal'}
    - Tone: ${song.features.spectralCentroid > 60 ? 'Bright and Airy' : 'Deep and Warm'}
    - Rhythm: ${song.features.tempo} BPM

    User Preference:
    - Prefers Intensity: ${userPref.energy}/100
    - Prefers Brightness: ${userPref.spectralCentroid}/100

    Write a single, natural sentence explaining the match. 
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || "This track perfectly complements the sound patterns in your recent playlist.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "This track aligns with the unique acoustic signature of your music library.";
  }
};

export const getLiveDiscovery = async (song: Song, userPref: AudioFeatures): Promise<LiveDiscovery> => {
  const prompt = `
    Search for 3-4 real-world songs released in 2024 or 2025 (or currently trending) that share a similar sonic profile with "${song.title}" by ${song.artist}.

    The target vibe is:
    - Energy: ${song.features.energy > 70 ? 'High' : 'Low/Moderate'}
    - Brightness/Tone: ${song.features.spectralCentroid > 60 ? 'Bright and crisp' : 'Dark and mellow'}
    - Tempo: ${song.features.tempo} BPM

    Explain concisely why these songs are recommended based on their acoustic similarities. Focus on sound, not just genre.
    Format your response as a clear markdown list of songs with brief explanations.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources: SearchSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || "Reference",
            uri: chunk.web.uri
          });
        }
      });
    }

    return {
      text: response.text || "No live discoveries found at this moment.",
      sources: sources
    };
  } catch (error) {
    console.error("Live Discovery Error:", error);
    return {
      text: "Could not fetch live recommendations at this time.",
      sources: []
    };
  }
};

