import { GoogleGenAI } from "@google/genai";
import { AudioFeatures, Song, LiveDiscovery, SearchSource } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Explains musical matches using the standard flash model for low latency.
 */
export const getMusicalExplanation = async (song: Song, userPref: AudioFeatures): Promise<string> => {
  const prompt = `
    Acts as a intuitive music discovery AI. Explain why a song matches a user's current "vibe" based on underlying acoustic patterns.

    CRITICAL: DO NOT mention technical terms like MFCC, Spectral Centroid, ZCR, or Chroma. 

    Target Song: "${song.title}" by ${song.artist}
    Acoustic Profile:
    - Vibe: ${song.features.energy > 70 ? 'High Energy' : 'Chilled'}
    - Texture: ${song.features.mfccs > 60 ? 'Rich and Layered' : 'Clean and Minimal'}
    - Tone: ${song.features.spectralCentroid > 60 ? 'Bright and Airy' : 'Deep and Warm'}
    - Rhythm: ${song.features.tempo} BPM

    Write a single, natural sentence explaining the match. 
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || "This track perfectly complements the sound patterns in your recent playlist.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "This track aligns with the unique acoustic signature of your music library.";
  }
};

/**
 * Standard search grounding for discovery.
 */
export const getLiveDiscovery = async (song: Song, userPref: AudioFeatures): Promise<LiveDiscovery> => {
  const prompt = `
    Search for 3-4 real-world songs released in 2024 or 2025 that share a similar sonic profile with "${song.title}" by ${song.artist}.
    Focus on Energy: ${song.features.energy}, Tempo: ${song.features.tempo}.
    Format as markdown list.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    return processSearchResponse(response);
  } catch (error) {
    console.error("Live Discovery Error:", error);
    return { text: "Could not fetch live recommendations.", sources: [] };
  }
};

/**
 * ADVANCED THINKING MODE: Uses Gemini 3 Pro to handle complex feedback-driven refinement.
 */
export const getComplexRefinement = async (
  currentSong: Song, 
  userPref: AudioFeatures, 
  feedback: boolean
): Promise<LiveDiscovery> => {
  const prompt = `
    COMPLEX QUERY: The user just listened to "${currentSong.title}" by ${currentSong.artist} and provided feedback: ${feedback ? 'POSITIVE (Liked it)' : 'NEGATIVE (Disliked it)'}.

    User Sonic Profile (Averages):
    - Energy: ${userPref.energy}
    - Brightness: ${userPref.spectralCentroid}
    - Complexity: ${userPref.mfccs}
    - Tempo: ${userPref.tempo}

    TASK: 
    1. Reason deeply about why the user might have ${feedback ? 'loved' : 'rejected'} this song based on the profile.
    2. If negative, identify which acoustic dimension to pivot away from.
    3. Use Google Search to find 3 groundbreaking or trending tracks (2024-2025) that satisfy this refined preference.
    4. Provide a high-intelligence explanation for the pivot/reinforcement.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        tools: [{ googleSearch: {} }],
      },
    });

    return processSearchResponse(response);
  } catch (error) {
    console.error("Pro Thinking Error:", error);
    return getLiveDiscovery(currentSong, userPref); // Fallback
  }
};

const processSearchResponse = (response: any): LiveDiscovery => {
  const sources: SearchSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          title: chunk.web.title || "Reference",
          uri: chunk.web.uri
        });
      }
    });
  }

  return {
    text: response.text || "No insights found.",
    sources: sources
  };
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

const App: React.FC = () => {
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [spotifyConnected, setSpotifyConnected] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle 10-second feedback trigger
  useEffect(() => {
    if (selectedSong && spotifyConnected) {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);

      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); // Trigger after 10 seconds of "listening"
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, spotifyConnected]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...library]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 2);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        // Complex thinking branch
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, [library]);

  const handleSpotifyLogin = () => {
    setIsLoggingIn(true);
    const width = 500;
    const height = 700;
    const left = window.screenX + (window.outerWidth - width) / 2;
    const top = window.screenY + (window.outerHeight - height) / 2;
    const loginWindow = window.open(
      'https://accounts.spotify.com/en/login?continue=https:%2F%2Fopen.spotify.com%2F',
      'SpotifyLogin',
      `width=${width},height=${height},left=${left},top=${top},status=no,resizable=yes`
    );
    const checkInterval = setInterval(() => {
      if (!loginWindow || loginWindow.closed) {
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 1000);
    setTimeout(() => {
      if (loginWindow && !loginWindow.closed) {
        loginWindow.close();
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 6000);
  };

  const startSyncProcess = () => {
    setIsLoggingIn(false);
    setIsImporting(true);
    setSyncLogs(['Requesting access to user_library scope...', 'Connection established.']);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 600));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Authenticating session...', 'Session Valid.']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Analyzing: ${song.title}`);
        setSyncLogs(prev => [...prev, `[EXTRACTOR] Processing waveform for "${song.artist} - ${song.title}"`]);
        setImportProgress(25 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 60));
        await new Promise(r => setTimeout(r, 200));
      }

      setImportProgress(100);
      await new Promise(r => setTimeout(r, 500));
      setLibrary(IMPORTED_USER_LIBRARY);
      setSpotifyConnected(true);
      setIsImporting(false);
      handleSelectSong(IMPORTED_USER_LIBRARY[0]);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    // Modal will show automatically after 10s via useEffect

    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;

    setSearchLoading(true);
    setIsThinking(true);

    try {
      // Trigger Gemini 3 Pro Thinking Refinement
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      // Adjust local vector if rejected
      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 30)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  if (!spotifyConnected && !isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full">
          <div className="w-28 h-28 bg-white rounded-[2.5rem] flex items-center justify-center mb-12 shadow-[0_0_60px_rgba(29,185,84,0.15)] transform -rotate-3">
            <i className="fas fa-wave-square text-black text-6xl"></i>
          </div>
          <div className="text-center mb-12">
            <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
            <p className="text-gray-400 text-lg font-medium max-w-md mx-auto leading-relaxed">
              Unlock your library's hidden acoustic signature. Connect your Spotify account to sync your tracks.
            </p>
          </div>
          <button onClick={handleSpotifyLogin} className="group w-full max-w-sm py-6 bg-[#1DB954] hover:bg-[#1ed760] text-black font-black rounded-full flex items-center justify-center gap-5 transition-all transform hover:scale-[1.05] active:scale-[0.98]">
            {isLoggingIn ? 'AWAITING AUTH...' : <><i className="fab fa-spotify text-4xl"></i><span className="text-xl">CONNECT SPOTIFY</span></>}
          </button>
          <p className="mt-12 text-[10px] text-gray-700 uppercase tracking-[0.4em] font-black">Thinking Engine: Gemini 3 Pro Ready</p>
        </div>
      </div>
    );
  }

  if (isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12">
        <div className="w-full max-w-3xl bg-[#0a0a0a] rounded-[4rem] border border-white/10 overflow-hidden h-[600px] flex flex-col">
          <div className="p-12 flex flex-col items-center border-b border-white/5">
            <SonicOrb energy={70} brightness={85} intensity={90} />
            <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Initializing Signal Lab'}</h2>
            <div className="w-full h-2 bg-white/5 rounded-full mt-8 overflow-hidden"><div className="h-full bg-[#1DB954]" style={{ width: `${importProgress}%` }}></div></div>
          </div>
          <div className="flex-1 overflow-y-auto p-10 font-mono text-[10px] text-[#1DB954]/60 space-y-3 bg-black/50 custom-scrollbar">
            {syncLogs.map((log, i) => <div key={i} className="flex gap-5 animate-fade-in"><span className="opacity-20 text-white">[{new Date().toLocaleTimeString()}]</span><span>{log}</span></div>)}
            <div ref={logsEndRef} />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-40">
        <div className="flex items-center gap-3 px-2">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-4 px-2 text-gray-400">
          <div className="flex items-center gap-4 hover:text-white transition-colors cursor-pointer py-1 font-black text-sm"><i className="fas fa-brain text-[#1DB954]"></i> Thinking Lab</div>
          <div className="flex items-center gap-4 text-white py-1 font-black text-sm underline decoration-2 underline-offset-8 decoration-[#1DB954]"><i className="fas fa-compact-disc"></i> Spotify Synced</div>
        </div>
        <div className="flex-1 overflow-y-auto pt-6 border-t border-white/5 px-2">
          <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4">Neural Clusters</p>
          {['Deep Bass', 'Timbral Brightness', 'Harmonic Flux'].map(p => (
            <div key={p} className="flex items-center gap-3 text-xs text-gray-500 hover:text-gray-200 cursor-pointer py-2 group"><i className="fas fa-project-diagram text-[10px] opacity-40"></i> {p}</div>
          ))}
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-[#0a0a0a] overflow-hidden relative">
        <header className="h-24 flex items-center justify-between px-12 backdrop-blur-md border-b border-white/[0.03] z-20">
          <h2 className="text-xl font-black text-white tracking-tight uppercase italic">Active Session <span className="text-[#1DB954] text-sm ml-2">● Synced</span></h2>
          <div className="bg-white/5 px-5 py-2.5 rounded-full flex items-center gap-4 border border-white/5">
            <div className="w-8 h-8 bg-[#1DB954] rounded-full flex items-center justify-center text-xs text-black font-black">SP</div>
            <span className="text-xs font-black text-gray-100">Library Active</span>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-12 custom-scrollbar">
          <section className="mb-20">
            <div className="flex items-end justify-between mb-10">
               <div className="max-w-xl">
                  <h2 className="text-5xl font-black tracking-tighter text-white mb-4">Latent Map</h2>
                  <p className="text-gray-500 font-medium text-lg leading-relaxed">Neural projection of your {library.length} tracks. Your acoustic DNA is mapped across two main latent dimensions.</p>
               </div>
            </div>
            <div className="bg-white/[0.02] rounded-[4rem] border border-white/5 p-6 shadow-2xl">
              <EmbeddingMap songs={library} selectedSongId={selectedSong?.id} onSelectSong={handleSelectSong} />
            </div>
          </section>

          <section>
            <div className="flex items-center justify-between mb-12 border-b border-white/5 pb-6">
              <h3 className="text-3xl font-black tracking-tighter text-white uppercase italic">Your Synced Collection</h3>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-6 gap-8 pb-40">
              {library.map(song => (
                <div key={song.id} onClick={() => handleSelectSong(song)} className={`group p-6 rounded-[3rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center ${selectedSong?.id === song.id ? 'bg-[#1DB954]/15 ring-2 ring-[#1DB954]/40' : 'bg-white/[0.03] hover:bg-white/[0.08]'}`}>
                  <div className="aspect-square w-full bg-black rounded-[2.5rem] mb-6 flex items-center justify-center shadow-2xl overflow-hidden group-hover:scale-[1.05] transition-transform">
                    <i className={`fas fa-compact-disc text-5xl ${selectedSong?.id === song.id ? 'text-[#1DB954] animate-spin-slow' : 'text-gray-800'}`}></i>
                  </div>
                  <h4 className="font-black text-sm truncate w-full text-gray-100">{song.title}</h4>
                  <p className="text-[10px] text-gray-500 truncate w-full mt-1 font-black uppercase tracking-tighter">{song.artist}</p>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* PROACTIVE FEEDBACK OVERLAY (Triggered after 10s) */}
        {showFeedback && (
          <div className="absolute bottom-16 left-1/2 -translate-x-1/2 w-full max-w-sm px-6 animate-slide-up z-50">
            <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl border border-white/10 flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-[#1DB954] rounded-3xl flex items-center justify-center mb-6 rotate-3 shadow-xl">
                <i className="fas fa-brain text-black text-2xl"></i>
              </div>
              <p className="text-black font-black text-[10px] uppercase tracking-[0.4em] mb-3">Pattern Check</p>
              <h4 className="text-gray-950 text-xl font-black mb-8 leading-tight tracking-tighter italic">Enjoying this discovery match?</h4>
              <div className="flex gap-4 w-full">
                <button onClick={() => submitFeedback(true)} className="flex-1 py-4 bg-black text-white text-[11px] font-black rounded-[2rem] hover:scale-105 transition-all">YES, MORE</button>
                <button onClick={() => submitFeedback(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 text-[11px] font-black rounded-[2rem] hover:bg-gray-200 transition-all">NOT QUITE</button>
              </div>
            </div>
          </div>
        )}
      </main>

      <aside className="w-[28rem] bg-black border-l border-white/5 flex flex-col p-10 overflow-hidden relative shadow-2xl z-40">
        <div className="flex items-center justify-between mb-10">
          <p className="text-[10px] font-black uppercase tracking-[0.6em] text-gray-600">The AI Musologist</p>
          <div className={`flex items-center gap-3 px-3 py-1 rounded-full border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/20 border-indigo-500 animate-pulse' : 'bg-[#1DB954]/5 border-[#1DB954]/10'}`}>
             <div className={`w-2 h-2 rounded-full ${isThinking ? 'bg-indigo-400' : 'bg-[#1DB954]'}`}></div>
             <span className={`text-[10px] font-black uppercase tracking-widest ${isThinking ? 'text-indigo-400' : 'text-[#1DB954]'}`}>{isThinking ? 'Thinking...' : 'Active'}</span>
          </div>
        </div>

        <div className="flex-none mb-10">
           <SonicOrb energy={userProfile.preferenceVector.energy} brightness={userProfile.preferenceVector.spectralCentroid} intensity={userProfile.preferenceVector.mfccs} />
           <div className="text-center mt-6">
              <p className="text-[11px] text-indigo-400 font-black uppercase tracking-[0.3em] italic opacity-80">{isThinking ? 'Deep Neural Reasoning Engaged' : 'Synthesizing Latent Matrix'}</p>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 space-y-12 custom-scrollbar pb-32">
          <section>
            <h3 className="text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 border-[#1DB954] pl-4">Internal Matches</h3>
            <div className="space-y-6">
              {loading ? <div className="h-32 bg-white/5 rounded-[3rem] animate-pulse"></div> : recommendations.map((rec) => (
                <div key={rec.song.id} className="group relative bg-white/[0.02] p-8 rounded-[3rem] border border-white/5 hover:border-[#1DB954]/50 transition-all cursor-pointer" onClick={() => handleSelectSong(rec.song)}>
                  <div className="flex items-center justify-between mb-4">
                     <span className="text-[10px] font-black text-[#1DB954]">{Math.round(rec.similarity * 100)}% Match</span>
                  </div>
                  <h4 className="font-black text-base text-white group-hover:text-[#1DB954] transition-colors">{rec.song.title}</h4>
                  <p className="text-xs text-gray-500 font-black uppercase mb-4">{rec.song.artist}</p>
                  <p className="text-[11px] text-gray-400 leading-relaxed italic opacity-80 bg-black/30 p-4 rounded-2xl">"{rec.explanation}"</p>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className={`text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 pl-4 transition-colors duration-1000 ${isThinking ? 'border-indigo-500' : 'border-indigo-800/40'}`}>
              Global Discovery {isThinking && <i className="fas fa-network-wired animate-bounce"></i>}
            </h3>
            <div className="space-y-6">
              {searchLoading ? <div className="h-48 bg-white/5 rounded-[3rem] animate-pulse"></div> : liveDiscovery && (
                <div className="animate-fade-in space-y-6">
                  <div className={`p-8 rounded-[3rem] border transition-colors duration-1000 ${isThinking ? 'bg-indigo-500/5 border-indigo-500/20 shadow-[0_0_40px_rgba(99,102,241,0.1)]' : 'bg-white/[0.01] border-white/5'}`}>
                    <div className="text-[11px] text-gray-400 leading-relaxed font-medium mb-8 bg-black/20 p-5 rounded-3xl">
                      {liveDiscovery.text.split('\n').map((line, i) => <p key={i} className="mb-3">{line}</p>)}
                    </div>
                    {liveDiscovery.sources.length > 0 && (
                      <div className="pt-6 border-t border-white/5 space-y-3">
                        {liveDiscovery.sources.map((src, idx) => (
                          <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="px-5 py-3 bg-white/5 hover:bg-white/10 rounded-2xl text-[10px] text-gray-400 flex items-center justify-between border border-white/5">
                            <span className="truncate">{src.title}</span>
                            <i className="fas fa-external-link-alt text-[8px]"></i>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </section>
        </div>
      </aside>

      <footer className="fixed bottom-0 left-0 right-0 h-32 bg-black/95 border-t border-white/5 px-12 flex items-center justify-between z-50">
        <div className="flex items-center gap-8 w-1/4">
          {selectedSong ? (
            <>
              <div className="w-20 h-20 bg-gray-900 rounded-[2.5rem] flex items-center justify-center border border-white/5 overflow-hidden">
                <i className="fas fa-compact-disc text-[#1DB954] text-4xl animate-spin-slow"></i>
              </div>
              <div className="min-w-0">
                <p className="text-base font-black text-white truncate">{selectedSong.title}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mt-1">{selectedSong.artist}</p>
              </div>
            </>
          ) : <div className="text-[10px] text-gray-500 font-black uppercase tracking-widest opacity-40">Standby</div>}
        </div>
        <div className="flex flex-col items-center gap-5 w-1/2">
          <div className="flex items-center gap-14 text-white/40">
            <i className="fas fa-random"></i> <i className="fas fa-step-backward text-xl"></i>
            <button className="w-16 h-16 bg-white text-black rounded-full flex items-center justify-center shadow-xl"><i className="fas fa-play text-2xl ml-1"></i></button>
            <i className="fas fa-step-forward text-xl"></i> <i className="fas fa-redo"></i>
          </div>
          <div className="w-full h-1.5 bg-white/10 rounded-full"></div>
        </div>
        <div className="w-1/4 flex justify-end items-center gap-6"><i className="fas fa-volume-up text-gray-600"></i><div className="w-32 h-1.5 bg-white/10 rounded-full"></div></div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); border-radius: 10px; }
        .animate-spin-slow { animation: spin 20s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.8s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.8s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

const App: React.FC = () => {
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [spotifyConnected, setSpotifyConnected] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  // Using ReturnType<typeof setTimeout> instead of NodeJS.Timeout to avoid namespace error in browser environment
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle 10-second feedback trigger
  useEffect(() => {
    if (selectedSong && spotifyConnected) {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);

      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); // Trigger after 10 seconds of "listening"
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, spotifyConnected]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...library]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 2);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        // Complex thinking branch
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, [library]);

  const handleSpotifyLogin = () => {
    setIsLoggingIn(true);
    const width = 500;
    const height = 700;
    const left = window.screenX + (window.outerWidth - width) / 2;
    const top = window.screenY + (window.outerHeight - height) / 2;
    const loginWindow = window.open(
      'https://accounts.spotify.com/en/login?continue=https:%2F%2Fopen.spotify.com%2F',
      'SpotifyLogin',
      `width=${width},height=${height},left=${left},top=${top},status=no,resizable=yes`
    );
    const checkInterval = setInterval(() => {
      if (!loginWindow || loginWindow.closed) {
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 1000);
    setTimeout(() => {
      if (loginWindow && !loginWindow.closed) {
        loginWindow.close();
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 6000);
  };

  const startSyncProcess = () => {
    setIsLoggingIn(false);
    setIsImporting(true);
    setSyncLogs(['Requesting access to user_library scope...', 'Connection established.']);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 600));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Authenticating session...', 'Session Valid.']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Analyzing: ${song.title}`);
        setSyncLogs(prev => [...prev, `[EXTRACTOR] Processing waveform for "${song.artist} - ${song.title}"`]);
        setImportProgress(25 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 60));
        await new Promise(r => setTimeout(r, 200));
      }

      setImportProgress(100);
      await new Promise(r => setTimeout(r, 500));
      setLibrary(IMPORTED_USER_LIBRARY);
      setSpotifyConnected(true);
      setIsImporting(false);
      handleSelectSong(IMPORTED_USER_LIBRARY[0]);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    // Modal will show automatically after 10s via useEffect

    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;

    setSearchLoading(true);
    setIsThinking(true);

    try {
      // Trigger Gemini 3 Pro Thinking Refinement
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      // Adjust local vector if rejected
      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 30)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  if (!spotifyConnected && !isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full">
          <div className="w-28 h-28 bg-white rounded-[2.5rem] flex items-center justify-center mb-12 shadow-[0_0_60px_rgba(29,185,84,0.15)] transform -rotate-3">
            <i className="fas fa-wave-square text-black text-6xl"></i>
          </div>
          <div className="text-center mb-12">
            <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
            <p className="text-gray-400 text-lg font-medium max-w-md mx-auto leading-relaxed">
              Unlock your library's hidden acoustic signature. Connect your Spotify account to sync your tracks.
            </p>
          </div>
          <button onClick={handleSpotifyLogin} className="group w-full max-w-sm py-6 bg-[#1DB954] hover:bg-[#1ed760] text-black font-black rounded-full flex items-center justify-center gap-5 transition-all transform hover:scale-[1.05] active:scale-[0.98]">
            {isLoggingIn ? 'AWAITING AUTH...' : <><i className="fab fa-spotify text-4xl"></i><span className="text-xl">CONNECT SPOTIFY</span></>}
          </button>
          <p className="mt-12 text-[10px] text-gray-700 uppercase tracking-[0.4em] font-black">Thinking Engine: Gemini 3 Pro Ready</p>
        </div>
      </div>
    );
  }

  if (isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12">
        <div className="w-full max-w-3xl bg-[#0a0a0a] rounded-[4rem] border border-white/10 overflow-hidden h-[600px] flex flex-col">
          <div className="p-12 flex flex-col items-center border-b border-white/5">
            <SonicOrb energy={70} brightness={85} intensity={90} />
            <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Initializing Signal Lab'}</h2>
            <div className="w-full h-2 bg-white/5 rounded-full mt-8 overflow-hidden"><div className="h-full bg-[#1DB954]" style={{ width: `${importProgress}%` }}></div></div>
          </div>
          <div className="flex-1 overflow-y-auto p-10 font-mono text-[10px] text-[#1DB954]/60 space-y-3 bg-black/50 custom-scrollbar">
            {syncLogs.map((log, i) => <div key={i} className="flex gap-5 animate-fade-in"><span className="opacity-20 text-white">[{new Date().toLocaleTimeString()}]</span><span>{log}</span></div>)}
            <div ref={logsEndRef} />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-40">
        <div className="flex items-center gap-3 px-2">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-4 px-2 text-gray-400">
          <div className="flex items-center gap-4 hover:text-white transition-colors cursor-pointer py-1 font-black text-sm"><i className="fas fa-brain text-[#1DB954]"></i> Thinking Lab</div>
          <div className="flex items-center gap-4 text-white py-1 font-black text-sm underline decoration-2 underline-offset-8 decoration-[#1DB954]"><i className="fas fa-compact-disc"></i> Spotify Synced</div>
        </div>
        <div className="flex-1 overflow-y-auto pt-6 border-t border-white/5 px-2">
          <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4">Neural Clusters</p>
          {['Deep Bass', 'Timbral Brightness', 'Harmonic Flux'].map(p => (
            <div key={p} className="flex items-center gap-3 text-xs text-gray-500 hover:text-gray-200 cursor-pointer py-2 group"><i className="fas fa-project-diagram text-[10px] opacity-40"></i> {p}</div>
          ))}
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-[#0a0a0a] overflow-hidden relative">
        <header className="h-24 flex items-center justify-between px-12 backdrop-blur-md border-b border-white/[0.03] z-20">
          <h2 className="text-xl font-black text-white tracking-tight uppercase italic">Active Session <span className="text-[#1DB954] text-sm ml-2">● Synced</span></h2>
          <div className="bg-white/5 px-5 py-2.5 rounded-full flex items-center gap-4 border border-white/5">
            <div className="w-8 h-8 bg-[#1DB954] rounded-full flex items-center justify-center text-xs text-black font-black">SP</div>
            <span className="text-xs font-black text-gray-100">Library Active</span>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-12 custom-scrollbar">
          <section className="mb-20">
            <div className="flex items-end justify-between mb-10">
               <div className="max-w-xl">
                  <h2 className="text-5xl font-black tracking-tighter text-white mb-4">Latent Map</h2>
                  <p className="text-gray-500 font-medium text-lg leading-relaxed">Neural projection of your {library.length} tracks. Your acoustic DNA is mapped across two main latent dimensions.</p>
               </div>
            </div>
            <div className="bg-white/[0.02] rounded-[4rem] border border-white/5 p-6 shadow-2xl">
              <EmbeddingMap songs={library} selectedSongId={selectedSong?.id} onSelectSong={handleSelectSong} />
            </div>
          </section>

          <section>
            <div className="flex items-center justify-between mb-12 border-b border-white/5 pb-6">
              <h3 className="text-3xl font-black tracking-tighter text-white uppercase italic">Your Synced Collection</h3>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-6 gap-8 pb-40">
              {library.map(song => (
                <div key={song.id} onClick={() => handleSelectSong(song)} className={`group p-6 rounded-[3rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center ${selectedSong?.id === song.id ? 'bg-[#1DB954]/15 ring-2 ring-[#1DB954]/40' : 'bg-white/[0.03] hover:bg-white/[0.08]'}`}>
                  <div className="aspect-square w-full bg-black rounded-[2.5rem] mb-6 flex items-center justify-center shadow-2xl overflow-hidden group-hover:scale-[1.05] transition-transform">
                    <i className={`fas fa-compact-disc text-5xl ${selectedSong?.id === song.id ? 'text-[#1DB954] animate-spin-slow' : 'text-gray-800'}`}></i>
                  </div>
                  <h4 className="font-black text-sm truncate w-full text-gray-100">{song.title}</h4>
                  <p className="text-[10px] text-gray-500 truncate w-full mt-1 font-black uppercase tracking-tighter">{song.artist}</p>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* PROACTIVE FEEDBACK OVERLAY (Triggered after 10s) */}
        {showFeedback && (
          <div className="absolute bottom-16 left-1/2 -translate-x-1/2 w-full max-w-sm px-6 animate-slide-up z-50">
            <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl border border-white/10 flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-[#1DB954] rounded-3xl flex items-center justify-center mb-6 rotate-3 shadow-xl">
                <i className="fas fa-brain text-black text-2xl"></i>
              </div>
              <p className="text-black font-black text-[10px] uppercase tracking-[0.4em] mb-3">Pattern Check</p>
              <h4 className="text-gray-950 text-xl font-black mb-8 leading-tight tracking-tighter italic">Enjoying this discovery match?</h4>
              <div className="flex gap-4 w-full">
                <button onClick={() => submitFeedback(true)} className="flex-1 py-4 bg-black text-white text-[11px] font-black rounded-[2rem] hover:scale-105 transition-all">YES, MORE</button>
                <button onClick={() => submitFeedback(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 text-[11px] font-black rounded-[2rem] hover:bg-gray-200 transition-all">NOT QUITE</button>
              </div>
            </div>
          </div>
        )}
      </main>

      <aside className="w-[28rem] bg-black border-l border-white/5 flex flex-col p-10 overflow-hidden relative shadow-2xl z-40">
        <div className="flex items-center justify-between mb-10">
          <p className="text-[10px] font-black uppercase tracking-[0.6em] text-gray-600">The AI Musologist</p>
          <div className={`flex items-center gap-3 px-3 py-1 rounded-full border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/20 border-indigo-500 animate-pulse' : 'bg-[#1DB954]/5 border-[#1DB954]/10'}`}>
             <div className={`w-2 h-2 rounded-full ${isThinking ? 'bg-indigo-400' : 'bg-[#1DB954]'}`}></div>
             <span className={`text-[10px] font-black uppercase tracking-widest ${isThinking ? 'text-indigo-400' : 'text-[#1DB954]'}`}>{isThinking ? 'Thinking...' : 'Active'}</span>
          </div>
        </div>

        <div className="flex-none mb-10">
           <SonicOrb energy={userProfile.preferenceVector.energy} brightness={userProfile.preferenceVector.spectralCentroid} intensity={userProfile.preferenceVector.mfccs} />
           <div className="text-center mt-6">
              <p className="text-[11px] text-indigo-400 font-black uppercase tracking-[0.3em] italic opacity-80">{isThinking ? 'Deep Neural Reasoning Engaged' : 'Synthesizing Latent Matrix'}</p>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 space-y-12 custom-scrollbar pb-32">
          <section>
            <h3 className="text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 border-[#1DB954] pl-4">Internal Matches</h3>
            <div className="space-y-6">
              {loading ? <div className="h-32 bg-white/5 rounded-[3rem] animate-pulse"></div> : recommendations.map((rec) => (
                <div key={rec.song.id} className="group relative bg-white/[0.02] p-8 rounded-[3rem] border border-white/5 hover:border-[#1DB954]/50 transition-all cursor-pointer" onClick={() => handleSelectSong(rec.song)}>
                  <div className="flex items-center justify-between mb-4">
                     <span className="text-[10px] font-black text-[#1DB954]">{Math.round(rec.similarity * 100)}% Match</span>
                  </div>
                  <h4 className="font-black text-base text-white group-hover:text-[#1DB954] transition-colors">{rec.song.title}</h4>
                  <p className="text-xs text-gray-500 font-black uppercase mb-4">{rec.song.artist}</p>
                  <p className="text-[11px] text-gray-400 leading-relaxed italic opacity-80 bg-black/30 p-4 rounded-2xl">"{rec.explanation}"</p>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className={`text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 pl-4 transition-colors duration-1000 ${isThinking ? 'border-indigo-500' : 'border-indigo-800/40'}`}>
              Global Discovery {isThinking && <i className="fas fa-network-wired animate-bounce"></i>}
            </h3>
            <div className="space-y-6">
              {searchLoading ? <div className="h-48 bg-white/5 rounded-[3rem] animate-pulse"></div> : liveDiscovery && (
                <div className="animate-fade-in space-y-6">
                  <div className={`p-8 rounded-[3rem] border transition-colors duration-1000 ${isThinking ? 'bg-indigo-500/5 border-indigo-500/20 shadow-[0_0_40px_rgba(99,102,241,0.1)]' : 'bg-white/[0.01] border-white/5'}`}>
                    <div className="text-[11px] text-gray-400 leading-relaxed font-medium mb-8 bg-black/20 p-5 rounded-3xl">
                      {liveDiscovery.text.split('\n').map((line, i) => <p key={i} className="mb-3">{line}</p>)}
                    </div>
                    {liveDiscovery.sources.length > 0 && (
                      <div className="pt-6 border-t border-white/5 space-y-3">
                        {liveDiscovery.sources.map((src, idx) => (
                          <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="px-5 py-3 bg-white/5 hover:bg-white/10 rounded-2xl text-[10px] text-gray-400 flex items-center justify-between border border-white/5">
                            <span className="truncate">{src.title}</span>
                            <i className="fas fa-external-link-alt text-[8px]"></i>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </section>
        </div>
      </aside>

      <footer className="fixed bottom-0 left-0 right-0 h-32 bg-black/95 border-t border-white/5 px-12 flex items-center justify-between z-50">
        <div className="flex items-center gap-8 w-1/4">
          {selectedSong ? (
            <>
              <div className="w-20 h-20 bg-gray-900 rounded-[2.5rem] flex items-center justify-center border border-white/5 overflow-hidden">
                <i className="fas fa-compact-disc text-[#1DB954] text-4xl animate-spin-slow"></i>
              </div>
              <div className="min-w-0">
                <p className="text-base font-black text-white truncate">{selectedSong.title}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mt-1">{selectedSong.artist}</p>
              </div>
            </>
          ) : <div className="text-[10px] text-gray-500 font-black uppercase tracking-widest opacity-40">Standby</div>}
        </div>
        <div className="flex flex-col items-center gap-5 w-1/2">
          <div className="flex items-center gap-14 text-white/40">
            <i className="fas fa-random"></i> <i className="fas fa-step-backward text-xl"></i>
            <button className="w-16 h-16 bg-white text-black rounded-full flex items-center justify-center shadow-xl"><i className="fas fa-play text-2xl ml-1"></i></button>
            <i className="fas fa-step-forward text-xl"></i> <i className="fas fa-redo"></i>
          </div>
          <div className="w-full h-1.5 bg-white/10 rounded-full"></div>
        </div>
        <div className="w-1/4 flex justify-end items-center gap-6"><i className="fas fa-volume-up text-gray-600"></i><div className="w-32 h-1.5 bg-white/10 rounded-full"></div></div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); border-radius: 10px; }
        .animate-spin-slow { animation: spin 20s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.8s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.8s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

const App: React.FC = () => {
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [spotifyConnected, setSpotifyConnected] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle 10-second feedback trigger
  useEffect(() => {
    if (selectedSong && spotifyConnected) {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);

      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); // Trigger after 10 seconds of "listening"
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, spotifyConnected]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...library]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 2);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, [library]);

  const handleSpotifyLogin = () => {
    setIsLoggingIn(true);
    const width = 500;
    const height = 700;
    const left = window.screenX + (window.outerWidth - width) / 2;
    const top = window.screenY + (window.outerHeight - height) / 2;
    const loginWindow = window.open(
      'https://accounts.spotify.com/en/login?continue=https:%2F%2Fopen.spotify.com%2F',
      'SpotifyLogin',
      `width=${width},height=${height},left=${left},top=${top},status=no,resizable=yes`
    );
    const checkInterval = setInterval(() => {
      if (!loginWindow || loginWindow.closed) {
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 1000);
    setTimeout(() => {
      if (loginWindow && !loginWindow.closed) {
        loginWindow.close();
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 6000);
  };

  const startSyncProcess = () => {
    setIsLoggingIn(false);
    setIsImporting(true);
    setSyncLogs(['Requesting access to user_library scope...', 'Connection established.']);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 600));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Authenticating session...', 'Session Valid.']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Analyzing: ${song.title}`);
        setSyncLogs(prev => [...prev, `[EXTRACTOR] Processing waveform for "${song.artist} - ${song.title}"`]);
        setImportProgress(25 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 60));
        await new Promise(r => setTimeout(r, 200));
      }

      setImportProgress(100);
      await new Promise(r => setTimeout(r, 500));
      setLibrary(IMPORTED_USER_LIBRARY);
      setSpotifyConnected(true);
      setIsImporting(false);
      handleSelectSong(IMPORTED_USER_LIBRARY[0]);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const handleShareOnSpotify = (e: React.MouseEvent, song: Song) => {
    e.stopPropagation();
    const query = encodeURIComponent(`${song.title} ${song.artist}`);
    window.open(`https://open.spotify.com/search/${query}`, '_blank');
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;

    setSearchLoading(true);
    setIsThinking(true);

    try {
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 30)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  if (!spotifyConnected && !isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full">
          <div className="w-28 h-28 bg-white rounded-[2.5rem] flex items-center justify-center mb-12 shadow-[0_0_60px_rgba(29,185,84,0.15)] transform -rotate-3">
            <i className="fas fa-wave-square text-black text-6xl"></i>
          </div>
          <div className="text-center mb-12">
            <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
            <p className="text-gray-400 text-lg font-medium max-w-md mx-auto leading-relaxed">
              Unlock your library's hidden acoustic signature. Connect your Spotify account to sync your tracks.
            </p>
          </div>
          <button onClick={handleSpotifyLogin} className="group w-full max-w-sm py-6 bg-[#1DB954] hover:bg-[#1ed760] text-black font-black rounded-full flex items-center justify-center gap-5 transition-all transform hover:scale-[1.05] active:scale-[0.98]">
            {isLoggingIn ? 'AWAITING AUTH...' : <><i className="fab fa-spotify text-4xl"></i><span className="text-xl">CONNECT SPOTIFY</span></>}
          </button>
          <p className="mt-12 text-[10px] text-gray-700 uppercase tracking-[0.4em] font-black">Thinking Engine: Gemini 3 Pro Ready</p>
        </div>
      </div>
    );
  }

  if (isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12">
        <div className="w-full max-w-3xl bg-[#0a0a0a] rounded-[4rem] border border-white/10 overflow-hidden h-[600px] flex flex-col">
          <div className="p-12 flex flex-col items-center border-b border-white/5">
            <SonicOrb energy={70} brightness={85} intensity={90} />
            <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Initializing Signal Lab'}</h2>
            <div className="w-full h-2 bg-white/5 rounded-full mt-8 overflow-hidden"><div className="h-full bg-[#1DB954]" style={{ width: `${importProgress}%` }}></div></div>
          </div>
          <div className="flex-1 overflow-y-auto p-10 font-mono text-[10px] text-[#1DB954]/60 space-y-3 bg-black/50 custom-scrollbar">
            {syncLogs.map((log, i) => <div key={i} className="flex gap-5 animate-fade-in"><span className="opacity-20 text-white">[{new Date().toLocaleTimeString()}]</span><span>{log}</span></div>)}
            <div ref={logsEndRef} />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-40">
        <div className="flex items-center gap-3 px-2">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-4 px-2 text-gray-400">
          <div className="flex items-center gap-4 hover:text-white transition-colors cursor-pointer py-1 font-black text-sm"><i className="fas fa-brain text-[#1DB954]"></i> Thinking Lab</div>
          <div className="flex items-center gap-4 text-white py-1 font-black text-sm underline decoration-2 underline-offset-8 decoration-[#1DB954]"><i className="fas fa-compact-disc"></i> Spotify Synced</div>
        </div>
        <div className="flex-1 overflow-y-auto pt-6 border-t border-white/5 px-2">
          <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4">Neural Clusters</p>
          {['Deep Bass', 'Timbral Brightness', 'Harmonic Flux'].map(p => (
            <div key={p} className="flex items-center gap-3 text-xs text-gray-500 hover:text-gray-200 cursor-pointer py-2 group"><i className="fas fa-project-diagram text-[10px] opacity-40"></i> {p}</div>
          ))}
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-[#0a0a0a] overflow-hidden relative">
        <header className="h-24 flex items-center justify-between px-12 backdrop-blur-md border-b border-white/[0.03] z-20">
          <h2 className="text-xl font-black text-white tracking-tight uppercase italic">Active Session <span className="text-[#1DB954] text-sm ml-2">● Synced</span></h2>
          <div className="bg-white/5 px-5 py-2.5 rounded-full flex items-center gap-4 border border-white/5">
            <div className="w-8 h-8 bg-[#1DB954] rounded-full flex items-center justify-center text-xs text-black font-black">SP</div>
            <span className="text-xs font-black text-gray-100">Library Active</span>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-12 custom-scrollbar">
          <section className="mb-20">
            <div className="flex items-end justify-between mb-10">
               <div className="max-w-xl">
                  <h2 className="text-5xl font-black tracking-tighter text-white mb-4">Latent Map</h2>
                  <p className="text-gray-500 font-medium text-lg leading-relaxed">Neural projection of your {library.length} tracks. Your acoustic DNA is mapped across two main latent dimensions.</p>
               </div>
            </div>
            <div className="bg-white/[0.02] rounded-[4rem] border border-white/5 p-6 shadow-2xl">
              <EmbeddingMap songs={library} selectedSongId={selectedSong?.id} onSelectSong={handleSelectSong} />
            </div>
          </section>

          <section>
            <div className="flex items-center justify-between mb-12 border-b border-white/5 pb-6">
              <h3 className="text-3xl font-black tracking-tighter text-white uppercase italic">Your Synced Collection</h3>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-6 gap-8 pb-40">
              {library.map(song => (
                <div key={song.id} onClick={() => handleSelectSong(song)} className={`group p-6 rounded-[3rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center ${selectedSong?.id === song.id ? 'bg-[#1DB954]/15 ring-2 ring-[#1DB954]/40' : 'bg-white/[0.03] hover:bg-white/[0.08]'}`}>
                  <div className="aspect-square w-full bg-black rounded-[2.5rem] mb-6 flex items-center justify-center shadow-2xl overflow-hidden group-hover:scale-[1.05] transition-transform">
