                  <h4 className="font-black text-sm truncate w-full text-gray-100">{song.title}</h4>
                  <p className="text-[10px] text-gray-500 truncate w-full mt-1 font-black uppercase tracking-tighter">{song.artist}</p>
                </div>
              ))}
            </div>
          </section>
        </div>

        {showFeedback && (
          <div className="absolute bottom-16 left-1/2 -translate-x-1/2 w-full max-w-sm px-6 animate-slide-up z-50">
            <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl border border-white/10 flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-[#1DB954] rounded-3xl flex items-center justify-center mb-6 rotate-3 shadow-xl">
                <i className="fas fa-brain text-black text-2xl"></i>
              </div>
              <p className="text-black font-black text-[10px] uppercase tracking-[0.4em] mb-3">Pattern Check</p>
              <h4 className="text-gray-950 text-xl font-black mb-8 leading-tight tracking-tighter italic">Enjoying this discovery match?</h4>
              <div className="flex gap-4 w-full">
                <button onClick={() => submitFeedback(true)} className="flex-1 py-4 bg-black text-white text-[11px] font-black rounded-[2rem] hover:scale-105 transition-all">YES, MORE</button>
                <button onClick={() => submitFeedback(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 text-[11px] font-black rounded-[2rem] hover:bg-gray-200 transition-all">NOT QUITE</button>
              </div>
            </div>
          </div>
        )}
      </main>

      <aside className="w-[28rem] bg-black border-l border-white/5 flex flex-col p-10 overflow-hidden relative shadow-2xl z-40">
        <div className="flex items-center justify-between mb-10">
          <p className="text-[10px] font-black uppercase tracking-[0.6em] text-gray-600">The AI Musologist</p>
          <div className={`flex items-center gap-3 px-3 py-1 rounded-full border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/20 border-indigo-500 animate-pulse' : 'bg-[#1DB954]/5 border-[#1DB954]/10'}`}>
             <div className={`w-2 h-2 rounded-full ${isThinking ? 'bg-indigo-400' : 'bg-[#1DB954]'}`}></div>
             <span className={`text-[10px] font-black uppercase tracking-widest ${isThinking ? 'text-indigo-400' : 'text-[#1DB954]'}`}>{isThinking ? 'Thinking...' : 'Active'}</span>
          </div>
        </div>

        <div className="flex-none mb-10">
           <SonicOrb energy={userProfile.preferenceVector.energy} brightness={userProfile.preferenceVector.spectralCentroid} intensity={userProfile.preferenceVector.mfccs} />
           <div className="text-center mt-6">
              <p className="text-[11px] text-indigo-400 font-black uppercase tracking-[0.3em] italic opacity-80">{isThinking ? 'Deep Neural Reasoning Engaged' : 'Synthesizing Latent Matrix'}</p>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 space-y-12 custom-scrollbar pb-32">
          <section>
            <h3 className="text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 border-[#1DB954] pl-4">Internal Matches</h3>
            <div className="space-y-6">
              {loading ? <div className="h-32 bg-white/5 rounded-[3rem] animate-pulse"></div> : recommendations.map((rec) => (
                <div key={rec.song.id} className="group relative bg-white/[0.02] p-8 rounded-[3rem] border border-white/5 hover:border-[#1DB954]/50 transition-all cursor-pointer" onClick={() => handleSelectSong(rec.song)}>
                  <div className="flex items-center justify-between mb-4">
                     <span className="text-[10px] font-black text-[#1DB954]">{Math.round(rec.similarity * 100)}% Match</span>
                  </div>
                  <h4 className="font-black text-base text-white group-hover:text-[#1DB954] transition-colors">{rec.song.title}</h4>
                  <p className="text-xs text-gray-500 font-black uppercase mb-4">{rec.song.artist}</p>
                  <p className="text-[11px] text-gray-400 leading-relaxed italic opacity-80 bg-black/30 p-4 rounded-2xl mb-4">"{rec.explanation}"</p>

                  <button 
                    onClick={(e) => handleShareOnSpotify(e, rec.song)}
                    className="w-full py-2.5 bg-[#1DB954]/10 hover:bg-[#1DB954] text-[#1DB954] hover:text-black rounded-full text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 border border-[#1DB954]/20 hover:border-transparent"
                  >
                    <i className="fab fa-spotify text-sm"></i>
                    SHARE ON SPOTIFY
                  </button>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className={`text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 pl-4 transition-colors duration-1000 ${isThinking ? 'border-indigo-500' : 'border-indigo-800/40'}`}>
              Global Discovery {isThinking && <i className="fas fa-network-wired animate-bounce"></i>}
            </h3>
            <div className="space-y-6">
              {searchLoading ? <div className="h-48 bg-white/5 rounded-[3rem] animate-pulse"></div> : liveDiscovery && (
                <div className="animate-fade-in space-y-6">
                  <div className={`p-8 rounded-[3rem] border transition-colors duration-1000 ${isThinking ? 'bg-indigo-500/5 border-indigo-500/20 shadow-[0_0_40px_rgba(99,102,241,0.1)]' : 'bg-white/[0.01] border-white/5'}`}>
                    <div className="text-[11px] text-gray-400 leading-relaxed font-medium mb-8 bg-black/20 p-5 rounded-3xl">
                      {liveDiscovery.text.split('\n').map((line, i) => <p key={i} className="mb-3">{line}</p>)}
                    </div>
                    {liveDiscovery.sources.length > 0 && (
                      <div className="pt-6 border-t border-white/5 space-y-3">
                        {liveDiscovery.sources.map((src, idx) => (
                          <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="px-5 py-3 bg-white/5 hover:bg-white/10 rounded-2xl text-[10px] text-gray-400 flex items-center justify-between border border-white/5">
                            <span className="truncate">{src.title}</span>
                            <i className="fas fa-external-link-alt text-[8px]"></i>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </section>
        </div>
      </aside>

      <footer className="fixed bottom-0 left-0 right-0 h-32 bg-black/95 border-t border-white/5 px-12 flex items-center justify-between z-50">
        <div className="flex items-center gap-8 w-1/4">
          {selectedSong ? (
            <>
              <div className="w-20 h-20 bg-gray-900 rounded-[2.5rem] flex items-center justify-center border border-white/5 overflow-hidden">
                <i className="fas fa-compact-disc text-[#1DB954] text-4xl animate-spin-slow"></i>
              </div>
              <div className="min-w-0">
                <p className="text-base font-black text-white truncate">{selectedSong.title}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mt-1">{selectedSong.artist}</p>
              </div>
            </>
          ) : <div className="text-[10px] text-gray-500 font-black uppercase tracking-widest opacity-40">Standby</div>}
        </div>
        <div className="flex flex-col items-center gap-5 w-1/2">
          <div className="flex items-center gap-14 text-white/40">
            <i className="fas fa-random"></i> <i className="fas fa-step-backward text-xl"></i>
            <button className="w-16 h-16 bg-white text-black rounded-full flex items-center justify-center shadow-xl"><i className="fas fa-play text-2xl ml-1"></i></button>
            <i className="fas fa-step-forward text-xl"></i> <i className="fas fa-redo"></i>
          </div>
          <div className="w-full h-1.5 bg-white/10 rounded-full"></div>
        </div>
        <div className="w-1/4 flex justify-end items-center gap-6"><i className="fas fa-volume-up text-gray-600"></i><div className="w-32 h-1.5 bg-white/10 rounded-full"></div></div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); border-radius: 10px; }
        .animate-spin-slow { animation: spin 20s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.8s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.8s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

const App: React.FC = () => {
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [spotifyConnected, setSpotifyConnected] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle 10-second feedback trigger
  useEffect(() => {
    if (selectedSong && spotifyConnected) {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);

      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); // Trigger after 10 seconds of "listening"
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, spotifyConnected]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, targetLibrary: Song[], isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    // Crucial: Use the passed targetLibrary instead of state library to avoid race condition
    const sorted = [...targetLibrary]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 2);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, [library]); // Keep library as dependency but use targetLibrary for immediate updates

  const handleSpotifyLogin = () => {
    setIsLoggingIn(true);
    const width = 500;
    const height = 700;
    const left = window.screenX + (window.outerWidth - width) / 2;
    const top = window.screenY + (window.outerHeight - height) / 2;

    let loginWindow: Window | null = null;
    try {
      loginWindow = window.open(
        'https://accounts.spotify.com/en/login?continue=https:%2F%2Fopen.spotify.com%2F',
        'SpotifyLogin',
        `width=${width},height=${height},left=${left},top=${top},status=no,resizable=yes`
      );
    } catch (e) {
      console.warn("Popup blocked, proceeding to internal sync...");
    }

    const checkInterval = setInterval(() => {
      if (!loginWindow || loginWindow.closed) {
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 1000);

    // Safety timeout
    setTimeout(() => {
      if (loginWindow && !loginWindow.closed) {
        loginWindow.close();
        clearInterval(checkInterval);
        startSyncProcess();
      }
    }, 6000);
  };

  const startSyncProcess = () => {
    setIsLoggingIn(false);
    setIsImporting(true);
    setSyncLogs(['Initializing Secure Handshake...', 'Tunnel Established.']);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 600));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Authenticating session with Spotify API...', 'OAuth Tokens Verified.']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Acoustic Profiling: ${song.title}`);
        setSyncLogs(prev => [...prev, `[GENOME] Extracting acoustic signature for track #${i+1}...`]);
        setImportProgress(25 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 60));
        await new Promise(r => setTimeout(r, 150));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Finalizing manifold projection...', 'Library Synced.']);
      await new Promise(r => setTimeout(r, 500));

      setLibrary(IMPORTED_USER_LIBRARY);
      setSpotifyConnected(true);
      setIsImporting(false);

      // Select first song and update recommendations using the FRESH library
      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      // Update User Profile with first song
      const alpha = 0.35;
      const initialPref = { ...userProfile.preferenceVector };
      const newPref: AudioFeatures = {
        mfccs: Math.round(initialPref.mfccs * (1 - alpha) + firstSong.features.mfccs * alpha),
        spectralCentroid: Math.round(initialPref.spectralCentroid * (1 - alpha) + firstSong.features.spectralCentroid * alpha),
        zcr: Math.round(initialPref.zcr * (1 - alpha) + firstSong.features.zcr * alpha),
        chroma: Math.round(initialPref.chroma * (1 - alpha) + firstSong.features.chroma * alpha),
        tempo: Math.round(initialPref.tempo * (1 - alpha) + firstSong.features.tempo * alpha),
        energy: Math.round(initialPref.energy * (1 - alpha) + firstSong.features.energy * alpha),
      };

      setUserProfile(prev => ({
        ...prev,
        preferenceVector: newPref,
        history: [firstSong.id],
      }));

      // Directly call update with the new library to avoid state delay
      updateRecommendations(newPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const handleShareOnSpotify = (e: React.MouseEvent, song: Song) => {
    e.stopPropagation();
