          <p className="mt-12 text-[10px] text-gray-700 uppercase tracking-[0.4em] font-black">AI Intelligence: Gemini 3 Pro Ready</p>
        </div>
      </div>
    );
  }

  if (isImporting) {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12">
        <div className="w-full max-w-3xl bg-[#0a0a0a] rounded-[4rem] border border-white/10 overflow-hidden h-[600px] flex flex-col shadow-[0_0_100px_rgba(29,185,84,0.1)]">
