  };

  const startSyncProcess = () => {
    setAuthStep('syncing');
    setIsImporting(true);
    setSyncLogs(['Requesting access token...', 'Handshake successful.', 'Initializing Musologist Extraction Pipeline...']);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 800));
      setImportProgress(15);
      setSyncLogs(prev => [...prev, 'Session validated.', 'Syncing library metadata...']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Acoustic Profiling: ${song.title}`);
        setSyncLogs(prev => [...prev, `[GENOME] Extracting acoustic signature for "${song.artist} - ${song.title}"...`]);
        setImportProgress(25 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 60));
        await new Promise(r => setTimeout(r, 200));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Manifold projection complete.', 'Library Synchronized.']);
      await new Promise(r => setTimeout(r, 600));

      setLibrary(IMPORTED_USER_LIBRARY);
      setIsImporting(false);
      setAuthStep('authenticated');

      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      const alpha = 0.35;
      const initialPref = { ...userProfile.preferenceVector };
      const newPref: AudioFeatures = {
        mfccs: Math.round(initialPref.mfccs * (1 - alpha) + firstSong.features.mfccs * alpha),
        spectralCentroid: Math.round(initialPref.spectralCentroid * (1 - alpha) + firstSong.features.spectralCentroid * alpha),
        zcr: Math.round(initialPref.zcr * (1 - alpha) + firstSong.features.zcr * alpha),
        chroma: Math.round(initialPref.chroma * (1 - alpha) + firstSong.features.chroma * alpha),
        tempo: Math.round(initialPref.tempo * (1 - alpha) + firstSong.features.tempo * alpha),
        energy: Math.round(initialPref.energy * (1 - alpha) + firstSong.features.energy * alpha),
      };

      setUserProfile(prev => ({
        ...prev,
        preferenceVector: newPref,
        history: [firstSong.id],
      }));

      updateRecommendations(newPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
