          ) : <div className="text-[10px] text-gray-600 font-black uppercase tracking-[0.4em] opacity-40">Ready to Analyze</div>}
        </div>

        <div className="flex flex-col items-center gap-5 w-1/2">
          <div className="flex items-center gap-14 text-white/40">
            <i className="fas fa-random hover:text-[#1DB954] cursor-pointer transition-colors"></i> 
            <i className="fas fa-step-backward text-xl hover:text-white cursor-pointer transition-colors"></i>
            <button className="w-16 h-16 bg-white text-black rounded-full flex items-center justify-center shadow-2xl hover:scale-110 active:scale-95 transition-all">
              <i className="fas fa-play text-2xl ml-1"></i>
            </button>
            <i className="fas fa-step-forward text-xl hover:text-white cursor-pointer transition-colors"></i> 
            <i className="fas fa-redo hover:text-[#1DB954] cursor-pointer transition-colors"></i>
          </div>
          <div className="w-full max-w-xl h-1 bg-white/10 rounded-full relative overflow-hidden">
             <div className="absolute inset-y-0 left-0 bg-white rounded-full shadow-[0_0_10px_white]" style={{ width: '30%' }}></div>
          </div>
        </div>

        <div className="w-1/4 flex justify-end items-center gap-8">
           <i className="fas fa-volume-up text-gray-500"></i>
           <div className="w-32 h-1 bg-white/10 rounded-full relative">
              <div className="absolute inset-y-0 left-0 bg-gray-500 rounded-full" style={{ width: '70%' }}></div>
           </div>
        </div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); border-radius: 10px; }
        .animate-spin-slow { animation: spin 20s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.8s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.6s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

type AuthStep = 'landing' | 'google-auth' | 'syncing' | 'authenticated';

const App: React.FC = () => {
  const [authStep, setAuthStep] = useState<AuthStep>('landing');
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);

  // Auth State
  const [googleUser, setGoogleUser] = useState<{name: string, email: string} | null>(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle 10-second feedback trigger
  useEffect(() => {
    if (selectedSong && authStep === 'authenticated') {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);

      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); 
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, authStep]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, targetLibrary: Song[], isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...targetLibrary]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 2);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, []);

  const handleStartGoogleAuth = () => {
    setAuthStep('google-auth');
  };

  const handleSelectGoogleAccount = (name: string, email: string) => {
    setIsAuthenticating(true);
    setGoogleUser({ name, email });
    // Simulate secure Google token verification
    setTimeout(() => {
      setIsAuthenticating(false);
      startSyncProcess();
    }, 1500);
  };

  const startSyncProcess = () => {
    setAuthStep('syncing');
    setIsImporting(true);
    setSyncLogs(['Requesting OAuth 2.0 credentials...', 'Token exchange successful.', 'Initializing Neural Signal Pipeline...']);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 800));
      setImportProgress(15);
      setSyncLogs(prev => [...prev, 'Google Account verified.', 'Synchronizing metadata streams...']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Analyzing Waveform: ${song.title}`);
        setSyncLogs(prev => [...prev, `[GENOME] Extracting acoustic signature for "${song.artist} - ${song.title}"...`]);
        setImportProgress(25 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 60));
        await new Promise(r => setTimeout(r, 180));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Manifold projection complete.', 'Library Synchronized.']);
      await new Promise(r => setTimeout(r, 600));

      setLibrary(IMPORTED_USER_LIBRARY);
      setIsImporting(false);
      setAuthStep('authenticated');

      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      const alpha = 0.35;
      const initialPref = { ...userProfile.preferenceVector };
      const newPref: AudioFeatures = {
        mfccs: Math.round(initialPref.mfccs * (1 - alpha) + firstSong.features.mfccs * alpha),
        spectralCentroid: Math.round(initialPref.spectralCentroid * (1 - alpha) + firstSong.features.spectralCentroid * alpha),
        zcr: Math.round(initialPref.zcr * (1 - alpha) + firstSong.features.zcr * alpha),
        chroma: Math.round(initialPref.chroma * (1 - alpha) + firstSong.features.chroma * alpha),
        tempo: Math.round(initialPref.tempo * (1 - alpha) + firstSong.features.tempo * alpha),
        energy: Math.round(initialPref.energy * (1 - alpha) + firstSong.features.energy * alpha),
      };

      setUserProfile(prev => ({
        ...prev,
        preferenceVector: newPref,
        history: [firstSong.id],
      }));

      updateRecommendations(newPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const handleShareOnSpotify = (e: React.MouseEvent, song: Song) => {
    e.stopPropagation();
    const query = encodeURIComponent(`${song.title} ${song.artist}`);
    window.open(`https://open.spotify.com/search/${query}`, '_blank');
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;

    setSearchLoading(true);
    setIsThinking(true);

    try {
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 30)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  // 1. Landing View
  if (authStep === 'landing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full">
          <div className="w-28 h-28 bg-white rounded-[2.5rem] flex items-center justify-center mb-12 shadow-[0_0_60px_rgba(29,185,84,0.15)] transform -rotate-3 hover:rotate-0 transition-transform duration-500">
            <i className="fas fa-wave-square text-black text-6xl"></i>
          </div>
          <div className="text-center mb-12">
            <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
            <p className="text-gray-400 text-lg font-medium max-w-md mx-auto leading-relaxed">
              Unlock your digital acoustic signature. Connect your account to map your sonic identity through high-fidelity signal analysis.
            </p>
          </div>
          <button 
            onClick={handleStartGoogleAuth} 
            className="group w-full max-w-sm py-5 bg-white hover:bg-gray-100 text-gray-900 font-bold rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.05] active:scale-[0.98] shadow-2xl"
          >
            <img src="https://www.gstatic.com/images/branding/product/1x/googleg_48dp.png" alt="Google" className="w-8 h-8" />
            <span className="text-lg">Sign in with Google</span>
          </button>
          <p className="mt-12 text-[10px] text-gray-700 uppercase tracking-[0.4em] font-black">Intelligent Discovery Engine • Gemini 3 Pro</p>
        </div>
      </div>
    );
  }

  // 2. Google Auth Simulation
  if (authStep === 'google-auth') {
    return (
      <div className="fixed inset-0 bg-[#f7f7f7] z-[100] flex items-center justify-center p-6">
        <div className="w-full max-w-[450px] bg-white rounded-lg shadow-[0_2px_4px_rgba(0,0,0,.1),0_8px_16px_rgba(0,0,0,.1)] p-10 border border-[#dadce0] animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <img src="https://www.gstatic.com/images/branding/googlelogo/1x/googlelogo_color_92x30dp.png" alt="Google" className="mb-6 w-24" />
            <h2 className="text-2xl font-normal text-[#202124] mb-2">Choose an account</h2>
            <p className="text-base text-[#202124] mb-8">to continue to <span className="font-medium">Musologist</span></p>

            {isAuthenticating ? (
              <div className="flex flex-col items-center py-10">
                <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="mt-4 text-sm text-[#5f6368] font-medium">Verifying account...</p>
              </div>
            ) : (
              <div className="w-full space-y-0.5 border-t border-b border-[#dadce0]">
                <button 
                  onClick={() => handleSelectGoogleAccount('Alex Rivera', 'alex.rivera@gmail.com')}
                  className="w-full py-4 flex items-center gap-4 hover:bg-gray-50 transition-colors px-2 text-left group"
                >
                  <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white font-medium">A</div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#3c4043]">Alex Rivera</p>
                    <p className="text-xs text-[#5f6368]">alex.rivera@gmail.com</p>
                  </div>
                </button>
                <button 
                  onClick={() => handleSelectGoogleAccount('Guest User', 'guest@musologist.ai')}
                  className="w-full py-4 flex items-center gap-4 hover:bg-gray-50 transition-colors px-2 text-left border-t border-[#dadce0]"
                >
                  <div className="w-10 h-10 bg-gray-200 rounded-full flex items-center justify-center text-gray-600"><i className="fas fa-user-circle text-2xl"></i></div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#3c4043]">Use another account</p>
                  </div>
                </button>
              </div>
            )}

            <p className="mt-8 text-xs text-[#5f6368] leading-relaxed text-left w-full">
              To continue, Google will share your name, email address, language preference, and profile picture with Musologist. Before using this app, you can review Musologist’s <span className="text-blue-600 cursor-pointer">privacy policy</span> and <span className="text-blue-600 cursor-pointer">terms of service</span>.
            </p>
          </div>
        </div>
      </div>
    );
  }

  // 3. Syncing View
  if (authStep === 'syncing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12">
        <div className="w-full max-w-3xl bg-[#0a0a0a] rounded-[4rem] border border-white/10 overflow-hidden h-[600px] flex flex-col shadow-[0_0_100px_rgba(29,185,84,0.1)]">
          <div className="p-12 flex flex-col items-center border-b border-white/5 bg-gradient-to-b from-white/[0.03] to-transparent">
            <SonicOrb energy={70} brightness={85} intensity={90} />
            <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Decrypting Sonic Nodes'}</h2>
            <div className="w-full h-2 bg-white/5 rounded-full mt-8 overflow-hidden shadow-inner">
              <div className="h-full bg-gradient-to-r from-[#1DB954] to-[#1ed760] transition-all duration-300" style={{ width: `${importProgress}%` }}></div>
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-10 font-mono text-[10px] text-[#1DB954]/60 space-y-3 bg-black/50 custom-scrollbar">
            {syncLogs.map((log, i) => <div key={i} className="flex gap-5 animate-fade-in"><span className="opacity-20 text-white">[{new Date().toLocaleTimeString()}]</span><span>{log}</span></div>)}
            <div ref={logsEndRef} />
          </div>
        </div>
      </div>
    );
  }

  // 4. Authenticated View
  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-40">
        <div className="flex items-center gap-3 px-2">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl hover:scale-110 transition-transform cursor-pointer"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-4 px-2 text-gray-400">
          <div className="flex items-center gap-4 hover:text-white transition-colors cursor-pointer py-1 font-black text-sm group">
            <i className="fas fa-brain text-[#1DB954] group-hover:scale-110 transition-transform"></i> Thinking Lab
          </div>
          <div className="flex items-center gap-4 text-white py-1 font-black text-sm underline decoration-2 underline-offset-8 decoration-[#1DB954] group">
            <i className="fas fa-compact-disc group-hover:rotate-45 transition-transform"></i> Library Map
          </div>
        </div>
        <div className="flex-1 overflow-y-auto pt-6 border-t border-white/5 px-2 custom-scrollbar">
          <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4">Acoustic Clusters</p>
          {['Deep Bass Projection', 'Rhythmic Texture', 'Harmonic Fluency', 'Ethereal Space'].map(p => (
            <div key={p} className="flex items-center gap-3 text-xs text-gray-500 hover:text-gray-200 cursor-pointer py-2 group transition-colors">
              <i className="fas fa-project-diagram text-[10px] opacity-40 group-hover:opacity-100"></i> {p}
            </div>
          ))}
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-[#0a0a0a] overflow-hidden relative">
        <header className="h-24 flex items-center justify-between px-12 backdrop-blur-md border-b border-white/[0.03] z-20">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-white tracking-tight uppercase italic">Acoustic Workspace</h2>
            <span className="text-[10px] text-gray-600 font-black uppercase tracking-widest">Library: {library.length} Sonic Elements Synced</span>
          </div>
          <div className="bg-white/5 px-5 py-2.5 rounded-full flex items-center gap-4 border border-white/5 group hover:bg-white/10 transition-all cursor-pointer">
            <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-[10px] text-white font-black shadow-[0_0_15px_rgba(37,99,235,0.3)]">
              {googleUser?.name.charAt(0) || 'U'}
            </div>
            <div className="flex flex-col">
              <span className="text-xs font-black text-gray-100 leading-none truncate max-w-[120px]">{googleUser?.name || 'Verified User'}</span>
              <span className="text-[9px] text-blue-400 font-black uppercase tracking-tighter">● Google Synced</span>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-12 custom-scrollbar">
          <section className="mb-20">
            <div className="flex items-end justify-between mb-10">
               <div className="max-w-xl">
                  <h2 className="text-5xl font-black tracking-tighter text-white mb-4">Discovery Manifold</h2>
                  <p className="text-gray-500 font-medium text-lg leading-relaxed">High-dimensional signal projection. Similar acoustic profiles are grouped by their latent sound characteristics.</p>
               </div>
               <button className="px-6 py-3 bg-[#1DB954] text-black rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-green-500/10 hover:scale-105 transition-all">Re-Map Signals</button>
            </div>
            <div className="bg-white/[0.02] rounded-[4rem] border border-white/5 p-6 shadow-2xl overflow-hidden">
              <EmbeddingMap songs={library} selectedSongId={selectedSong?.id} onSelectSong={handleSelectSong} />
            </div>
          </section>

          <section>
            <div className="flex items-center justify-between mb-12 border-b border-white/5 pb-6">
              <h3 className="text-3xl font-black tracking-tighter text-white uppercase italic">Active Synced Tracks</h3>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-6 gap-8 pb-40">
              {library.map(song => (
                <div 
                  key={song.id} 
                  onClick={() => handleSelectSong(song)} 
                  className={`group p-6 rounded-[3rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center ${selectedSong?.id === song.id ? 'bg-[#1DB954]/15 ring-2 ring-[#1DB954]/40' : 'bg-white/[0.03] hover:bg-white/[0.08]'}`}
                >
                  <div className="aspect-square w-full bg-black rounded-[2.5rem] mb-6 flex items-center justify-center shadow-2xl overflow-hidden group-hover:scale-[1.05] transition-transform relative">
                    <i className={`fas fa-compact-disc text-5xl transition-all duration-1000 ${selectedSong?.id === song.id ? 'text-[#1DB954] animate-spin-slow' : 'text-gray-800'}`}></i>
                    {selectedSong?.id === song.id && <div className="absolute bottom-4 right-4 w-3 h-3 bg-[#1DB954] rounded-full animate-ping"></div>}
                  </div>
                  <h4 className="font-black text-sm truncate w-full text-gray-100">{song.title}</h4>
                  <p className="text-[10px] text-gray-500 truncate w-full mt-1 font-black uppercase tracking-tighter">{song.artist}</p>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* FEEDBACK OVERLAY (Triggered after 10s) */}
        {showFeedback && (
          <div className="absolute bottom-16 left-1/2 -translate-x-1/2 w-full max-w-sm px-6 animate-slide-up z-50">
            <div className="bg-white p-10 rounded-[3.5rem] shadow-[0_50px_100px_rgba(0,0,0,0.8)] border border-white/10 flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-[#1DB954] rounded-3xl flex items-center justify-center mb-6 rotate-3 shadow-xl shadow-green-500/20">
                <i className="fas fa-brain text-black text-2xl"></i>
              </div>
              <p className="text-black font-black text-[10px] uppercase tracking-[0.4em] mb-3">Feedback Loop</p>
              <h4 className="text-gray-950 text-xl font-black mb-8 leading-tight tracking-tighter italic">Is our acoustic match hitting the target?</h4>
              <div className="flex gap-4 w-full">
                <button onClick={() => submitFeedback(true)} className="flex-1 py-4 bg-black text-white text-[11px] font-black rounded-[2rem] hover:scale-105 transition-all shadow-xl">YES, MORE</button>
                <button onClick={() => submitFeedback(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 text-[11px] font-black rounded-[2rem] hover:bg-gray-200 transition-all">RE-EVALUATE</button>
              </div>
            </div>
          </div>
        )}
      </main>

      <aside className="w-[28rem] bg-black border-l border-white/5 flex flex-col p-10 overflow-hidden relative shadow-2xl z-40">
        <div className="flex items-center justify-between mb-10">
          <p className="text-[10px] font-black uppercase tracking-[0.6em] text-gray-600">The Musologist AI</p>
          <div className={`flex items-center gap-3 px-3 py-1 rounded-full border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/20 border-indigo-500/50 animate-pulse' : 'bg-[#1DB954]/5 border-[#1DB954]/10'}`}>
             <div className={`w-2 h-2 rounded-full ${isThinking ? 'bg-indigo-400' : 'bg-[#1DB954]'}`}></div>
             <span className={`text-[10px] font-black uppercase tracking-widest ${isThinking ? 'text-indigo-400' : 'text-[#1DB954]'}`}>{isThinking ? 'Thinking...' : 'Stable'}</span>
          </div>
        </div>

        <div className="flex-none mb-10">
           <SonicOrb energy={userProfile.preferenceVector.energy} brightness={userProfile.preferenceVector.spectralCentroid} intensity={userProfile.preferenceVector.mfccs} />
           <div className="text-center mt-6">
              <p className="text-[11px] text-indigo-400 font-black uppercase tracking-[0.3em] italic opacity-80">{isThinking ? 'Engaging Deep Latent Search' : 'Synthesizing Sonic Clusters'}</p>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 space-y-12 custom-scrollbar pb-32">
          <section>
            <h3 className="text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 border-[#1DB954] pl-4">Latent Matches</h3>
            <div className="space-y-6">
              {loading ? <div className="h-32 bg-white/5 rounded-[3rem] animate-pulse"></div> : recommendations.map((rec) => (
                <div key={rec.song.id} className="group relative bg-white/[0.02] p-8 rounded-[3rem] border border-white/5 hover:border-[#1DB954]/50 transition-all cursor-pointer shadow-lg" onClick={() => handleSelectSong(rec.song)}>
                  <div className="flex items-center justify-between mb-4">
                     <span className="text-[10px] font-black text-[#1DB954] uppercase tracking-widest">{Math.round(rec.similarity * 100)}% Sonic Match</span>
                  </div>
                  <h4 className="font-black text-base text-white group-hover:text-[#1DB954] transition-colors">{rec.song.title}</h4>
                  <p className="text-xs text-gray-500 font-black uppercase mb-4">{rec.song.artist}</p>
                  <p className="text-[11px] text-gray-400 leading-relaxed italic opacity-80 bg-black/40 p-5 rounded-3xl mb-6 border border-white/5">"{rec.explanation}"</p>

                  <button 
                    onClick={(e) => handleShareOnSpotify(e, rec.song)}
                    className="w-full py-3 bg-[#1DB954]/10 hover:bg-[#1DB954] text-[#1DB954] hover:text-black rounded-full text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 border border-[#1DB954]/20 hover:border-transparent active:scale-95"
                  >
                    <i className="fab fa-spotify text-sm"></i>
                    SHARE ON SPOTIFY
                  </button>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className={`text-sm font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest border-l-4 pl-4 transition-colors duration-1000 ${isThinking ? 'border-indigo-500' : 'border-indigo-900/30'}`}>
              Global Acoustic Lab {isThinking && <i className="fas fa-network-wired animate-bounce text-indigo-400 ml-2"></i>}
            </h3>
            <div className="space-y-6">
              {searchLoading ? <div className="h-64 bg-white/5 rounded-[3rem] animate-pulse"></div> : liveDiscovery && (
                <div className="animate-fade-in space-y-6">
                  <div className={`p-8 rounded-[3rem] border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/5 border-indigo-500/30 shadow-[0_0_40px_rgba(99,102,241,0.1)]' : 'bg-white/[0.01] border-white/5 shadow-xl'}`}>
                    <div className="text-[11px] text-gray-400 leading-relaxed font-medium mb-8 bg-black/40 p-6 rounded-3xl border border-white/5">
                      {liveDiscovery.text.split('\n').map((line, i) => <p key={i} className="mb-3">{line}</p>)}
                    </div>
                    {liveDiscovery.sources.length > 0 && (
                      <div className="pt-6 border-t border-white/5 space-y-3">
                        <p className="text-[9px] font-black text-indigo-400/60 uppercase tracking-widest mb-2">Grounding Sources</p>
                        {liveDiscovery.sources.map((src, idx) => (
                          <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="px-5 py-4 bg-white/5 hover:bg-white/10 rounded-2xl text-[10px] text-gray-400 hover:text-white flex items-center justify-between border border-white/5 transition-all group">
                            <span className="truncate pr-4">{src.title}</span>
                            <i className="fas fa-external-link-alt text-[8px] opacity-30 group-hover:opacity-100 transition-opacity"></i>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </section>
        </div>
      </aside>

      <footer className="fixed bottom-0 left-0 right-0 h-32 bg-black/95 border-t border-white/5 px-12 flex items-center justify-between z-50">
        <div className="flex items-center gap-8 w-1/4">
          {selectedSong ? (
            <div className="flex items-center gap-6 animate-fade-in">
              <div className="w-20 h-20 bg-gray-900 rounded-[2.5rem] flex items-center justify-center border border-white/5 relative overflow-hidden">
                <i className="fas fa-compact-disc text-[#1DB954] text-4xl animate-spin-slow"></i>
              </div>
              <div className="min-w-0">
                <p className="text-base font-black text-white truncate">{selectedSong.title}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mt-1 opacity-70 italic">{selectedSong.artist}</p>
              </div>
            </div>
          ) : <div className="text-[10px] text-gray-600 font-black uppercase tracking-[0.4em] opacity-40">Ready to Analyze</div>}
        </div>

        <div className="flex flex-col items-center gap-5 w-1/2">
          <div className="flex items-center gap-14 text-white/40">
            <i className="fas fa-random hover:text-[#1DB954] cursor-pointer transition-colors"></i> 
            <i className="fas fa-step-backward text-xl hover:text-white cursor-pointer transition-colors"></i>
            <button className="w-16 h-16 bg-white text-black rounded-full flex items-center justify-center shadow-2xl hover:scale-110 active:scale-95 transition-all">
              <i className="fas fa-play text-2xl ml-1"></i>
            </button>
            <i className="fas fa-step-forward text-xl hover:text-white cursor-pointer transition-colors"></i> 
            <i className="fas fa-redo hover:text-[#1DB954] cursor-pointer transition-colors"></i>
          </div>
          <div className="w-full max-w-xl h-1 bg-white/10 rounded-full relative overflow-hidden">
             <div className="absolute inset-y-0 left-0 bg-white rounded-full shadow-[0_0_10px_white]" style={{ width: '30%' }}></div>
          </div>
        </div>

        <div className="w-1/4 flex justify-end items-center gap-8">
           <i className="fas fa-volume-up text-gray-500"></i>
           <div className="w-32 h-1 bg-white/10 rounded-full relative">
              <div className="absolute inset-y-0 left-0 bg-gray-500 rounded-full" style={{ width: '70%' }}></div>
           </div>
        </div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); border-radius: 10px; }
        .animate-spin-slow { animation: spin 20s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.8s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.6s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

type AuthStep = 'landing' | 'google-auth' | 'syncing' | 'authenticated';

const App: React.FC = () => {
  const [authStep, setAuthStep] = useState<AuthStep>('landing');
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);

  // Auth State
  const [googleUser, setGoogleUser] = useState<{name: string, email: string} | null>(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle 10-second feedback trigger
  useEffect(() => {
    if (selectedSong && authStep === 'authenticated') {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);

      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); 
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, authStep]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, targetLibrary: Song[], isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...targetLibrary]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Interpreting sound patterns...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 2);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, []);

  const handleStartGoogleAuth = () => {
    setAuthStep('google-auth');
  };

  const handleSelectGoogleAccount = (name: string, email: string) => {
    setIsAuthenticating(true);
    setGoogleUser({ name, email });
    // Simulate secure Google token verification
    setTimeout(() => {
      setIsAuthenticating(false);
      startSyncProcess(email);
    }, 1500);
  };

  const startSyncProcess = (email: string) => {
    setAuthStep('syncing');
    setIsImporting(true);
    setSyncLogs([
      `Querying Spotify credentials linked to ${email}...`,
      'Google SSO handshake verified.',
      'Detected linked Spotify account: "CloudExplorer_99"',
      'Identifying active playlists...'
    ]);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 1000));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Found: "My Discoveries" Playlist (12 tracks)', 'Initiating signal genome extraction...']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Analyzing Waveform: ${song.title}`);
        setSyncLogs(prev => [...prev, `[GENOME] Extracting acoustic signature for track #${i+1}...`]);
        setImportProgress(20 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 70));
        await new Promise(r => setTimeout(r, 150));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Neural manifold projection complete.', 'Workspace Synchronized.']);
      await new Promise(r => setTimeout(r, 600));

      setLibrary(IMPORTED_USER_LIBRARY);
      setIsImporting(false);
      setAuthStep('authenticated');

      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      const alpha = 0.35;
      const initialPref = { ...userProfile.preferenceVector };
      const newPref: AudioFeatures = {
        mfccs: Math.round(initialPref.mfccs * (1 - alpha) + firstSong.features.mfccs * alpha),
        spectralCentroid: Math.round(initialPref.spectralCentroid * (1 - alpha) + firstSong.features.spectralCentroid * alpha),
        zcr: Math.round(initialPref.zcr * (1 - alpha) + firstSong.features.zcr * alpha),
        chroma: Math.round(initialPref.chroma * (1 - alpha) + firstSong.features.chroma * alpha),
        tempo: Math.round(initialPref.tempo * (1 - alpha) + firstSong.features.tempo * alpha),
        energy: Math.round(initialPref.energy * (1 - alpha) + firstSong.features.energy * alpha),
      };

      setUserProfile(prev => ({
        ...prev,
        preferenceVector: newPref,
        history: [firstSong.id],
      }));

      updateRecommendations(newPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const handleShareOnSpotify = (e: React.MouseEvent, song: Song) => {
    e.stopPropagation();
    const query = encodeURIComponent(`${song.title} ${song.artist}`);
    window.open(`https://open.spotify.com/search/${query}`, '_blank');
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;

    setSearchLoading(true);
    setIsThinking(true);

    try {
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 30)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  // 1. Landing View
  if (authStep === 'landing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full">
          <div className="w-28 h-28 bg-white rounded-[2.5rem] flex items-center justify-center mb-12 shadow-[0_0_60px_rgba(29,185,84,0.15)] transform -rotate-3 hover:rotate-0 transition-transform duration-500">
            <i className="fas fa-wave-square text-black text-6xl"></i>
          </div>
          <div className="text-center mb-12">
            <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
            <p className="text-gray-400 text-lg font-medium max-w-md mx-auto leading-relaxed">
              Unlock your digital acoustic signature. Sign in with Google to extract your linked Spotify playlists and map your sonic identity.
            </p>
          </div>
          <button 
            onClick={handleStartGoogleAuth} 
            className="group w-full max-w-sm py-5 bg-white hover:bg-gray-100 text-gray-900 font-bold rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.05] active:scale-[0.98] shadow-2xl"
          >
            <img src="https://www.gstatic.com/images/branding/product/1x/googleg_48dp.png" alt="Google" className="w-8 h-8" />
            <span className="text-lg">Sign in with Google</span>
          </button>
          <p className="mt-12 text-[10px] text-gray-700 uppercase tracking-[0.4em] font-black">Intelligent Discovery • Linked Spotify Sync</p>
        </div>
      </div>
    );
  }

  // 2. Google Auth Simulation
  if (authStep === 'google-auth') {
    return (
      <div className="fixed inset-0 bg-[#f7f7f7] z-[100] flex items-center justify-center p-6">
        <div className="w-full max-w-[450px] bg-white rounded-lg shadow-[0_2px_4px_rgba(0,0,0,.1),0_8px_16px_rgba(0,0,0,.1)] p-10 border border-[#dadce0] animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <img src="https://www.gstatic.com/images/branding/googlelogo/1x/googlelogo_color_92x30dp.png" alt="Google" className="mb-6 w-24" />
            <h2 className="text-2xl font-normal text-[#202124] mb-2">Choose an account</h2>
            <p className="text-base text-[#202124] mb-8">to continue to <span className="font-medium">Musologist</span></p>

            {isAuthenticating ? (
              <div className="flex flex-col items-center py-10">
                <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="mt-4 text-sm text-[#5f6368] font-medium">Verifying linked Spotify credentials...</p>
              </div>
            ) : (
              <div className="w-full space-y-0.5 border-t border-b border-[#dadce0]">
                <button 
                  onClick={() => handleSelectGoogleAccount('Alex Rivera', 'alex.rivera@gmail.com')}
                  className="w-full py-4 flex items-center gap-4 hover:bg-gray-50 transition-colors px-2 text-left group"
                >
                  <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white font-medium">A</div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#3c4043]">Alex Rivera</p>
                    <p className="text-xs text-[#5f6368]">alex.rivera@gmail.com</p>
                  </div>
                </button>
                <button 
                  onClick={() => handleSelectGoogleAccount('Guest Explorer', 'guest@musologist.ai')}
