        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.6s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

type AuthStep = 'landing' | 'google-auth' | 'syncing' | 'authenticated';
type Tab = 'thinking-lab' | 'spotify-sync';

const App: React.FC = () => {
  const [authStep, setAuthStep] = useState<AuthStep>('landing');
  const [activeTab, setActiveTab] = useState<Tab>('thinking-lab');
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Auth State
  const [googleUser, setGoogleUser] = useState<{name: string, email: string} | null>(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle feedback loop trigger
  useEffect(() => {
    if (selectedSong && authStep === 'authenticated') {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
      playbackTimerRef.current = setTimeout(() => {
        setShowFeedback(true);
      }, 10000); 
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, authStep]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, targetLibrary: Song[], isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...targetLibrary]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Synthesizing recommendation rationale...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 3);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, []);

  const handleStartGoogleAuth = () => {
    setAuthStep('google-auth');
  };

  const handleSelectGoogleAccount = (name: string, email: string) => {
    setIsAuthenticating(true);
    setGoogleUser({ name, email });
    setTimeout(() => {
      setIsAuthenticating(false);
      startSyncProcess(email);
    }, 1200);
  };

  const startSyncProcess = (email: string) => {
    setAuthStep('syncing');
    setIsImporting(true);
    setSyncLogs([
      `Authenticating ${email}...`,
      'Google SSO handshake verified.',
      'Fetching linked Spotify account permissions...',
      'Accessing "CloudExplorer_99" Spotify Library...'
    ]);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 800));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Found 12 high-match tracks in "Recent Discoveries" playlist.', 'Starting acoustic waveform decryption...']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Profiling: ${song.title}`);
        setSyncLogs(prev => [...prev, `[NEURAL] Mapping acoustic fingerprint for "${song.artist} - ${song.title}"...`]);
        setImportProgress(20 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 70));
        await new Promise(r => setTimeout(r, 150));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Manifold projection complete.', 'Spotify Library Synchronized.']);
      await new Promise(r => setTimeout(r, 600));

      setLibrary(IMPORTED_USER_LIBRARY);
      setIsImporting(false);
      setAuthStep('authenticated');
      setActiveTab('thinking-lab');

      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      const initialPref = firstSong.features;
      setUserProfile(prev => ({
        ...prev,
        preferenceVector: initialPref,
        history: [firstSong.id],
      }));

      updateRecommendations(initialPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;
    setSearchLoading(true);
    setIsThinking(true);
    setActiveTab('spotify-sync'); // Recommendations are now in Spotify Sync

    try {
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 20)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  const filteredLibrary = library.filter(song => 
    song.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    song.artist.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (authStep === 'landing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full text-center">
          <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center mb-10 shadow-[0_0_50px_rgba(29,185,84,0.1)] transform -rotate-3">
            <i className="fas fa-wave-square text-black text-5xl"></i>
          </div>
          <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
          <p className="text-gray-400 text-lg font-medium mb-10 leading-relaxed">
            The intelligent sonic laboratory. Sign in with Google to analyze your linked Spotify library and discover tracks through deep acoustic reasoning.
          </p>
          <button 
            onClick={handleStartGoogleAuth} 
            className="group w-full max-w-sm py-5 bg-white hover:bg-gray-100 text-gray-900 font-bold rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.05] active:scale-[0.98] shadow-2xl"
          >
            <img src="https://www.gstatic.com/images/branding/product/1x/googleg_48dp.png" alt="Google" className="w-8 h-8" />
            <span className="text-lg">Sign in with Google</span>
          </button>
        </div>
      </div>
    );
  }

  if (authStep === 'google-auth') {
    return (
      <div className="fixed inset-0 bg-[#f8f9fa] z-[100] flex items-center justify-center p-6">
        <div className="w-full max-w-[440px] bg-white rounded-lg shadow-xl p-10 border border-[#dadce0] animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <img src="https://www.gstatic.com/images/branding/googlelogo/1x/googlelogo_color_92x30dp.png" alt="Google" className="mb-6 w-24" />
            <h2 className="text-2xl font-normal text-[#202124] mb-2">Choose an account</h2>
            <p className="text-base text-[#202124] mb-8">to continue to <span className="font-medium">Musologist AI</span></p>
            {isAuthenticating ? (
              <div className="flex flex-col items-center py-10">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="mt-4 text-sm text-[#5f6368] font-medium">Connecting to Spotify Services...</p>
              </div>
            ) : (
              <div className="w-full border-t border-b border-[#dadce0] mb-8">
                <button 
                  onClick={() => handleSelectGoogleAccount('Alex Rivera', 'alex.rivera@gmail.com')}
                  className="w-full py-4 flex items-center gap-4 hover:bg-gray-50 transition-colors px-2 text-left group"
                >
                  <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white font-medium">A</div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#3c4043]">Alex Rivera</p>
                    <p className="text-xs text-[#5f6368]">alex.rivera@gmail.com</p>
                  </div>
                </button>
              </div>
            )}
            <p className="text-xs text-[#5f6368] text-left">
              Google will share your information with Musologist to link your Spotify playlist data securely.
            </p>
          </div>
        </div>
      </div>
    );
  }

  if (authStep === 'syncing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12 text-center">
        <div className="w-full max-w-2xl">
          <SonicOrb energy={70} brightness={85} intensity={90} />
          <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Extracting Spotify Genome'}</h2>
          <div className="w-full h-1.5 bg-white/5 rounded-full mt-8 overflow-hidden">
            <div className="h-full bg-[#1DB954] transition-all duration-300" style={{ width: `${importProgress}%` }}></div>
          </div>
          <div className="mt-12 h-40 overflow-hidden font-mono text-[10px] text-[#1DB954]/50 text-left space-y-2">
            {syncLogs.slice(-6).map((log, i) => <div key={i} className="animate-fade-in">>> {log}</div>)}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      {/* Sidebar Navigation */}
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-50">
        <div className="flex items-center gap-3 px-2 mb-4">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-2">
          <button 
            onClick={() => setActiveTab('thinking-lab')}
            className={`w-full flex items-center gap-4 py-3 px-4 rounded-xl font-black text-sm transition-all group ${activeTab === 'thinking-lab' ? 'bg-[#1DB954] text-black' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
          >
            <i className={`fas fa-brain transition-transform ${activeTab === 'thinking-lab' ? '' : 'group-hover:scale-110'}`}></i> Thinking Lab
          </button>
          <button 
            onClick={() => setActiveTab('spotify-sync')}
            className={`w-full flex items-center gap-4 py-3 px-4 rounded-xl font-black text-sm transition-all group ${activeTab === 'spotify-sync' ? 'bg-[#1DB954] text-black' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
          >
            <i className={`fas fa-sync-alt transition-transform ${activeTab === 'spotify-sync' ? 'rotate-180' : 'group-hover:rotate-180'}`}></i> Spotify Sync
          </button>
        </div>
        <div className="flex-1 border-t border-white/5 mt-4 pt-6 overflow-y-auto custom-scrollbar">
           <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4 px-4">Neural Clusters</p>
           {['Ethereal Ambient', 'Dynamic Funk', 'Melodic Soul', 'Sub-Bass Heavy'].map(cluster => (
             <div key={cluster} className="px-4 py-2 text-xs text-gray-500 hover:text-white cursor-pointer transition-colors flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-[#1DB954]/40"></span> {cluster}
             </div>
           ))}
        </div>
        <div className="p-4 bg-white/5 rounded-2xl border border-white/5">
           <div className="flex items-center gap-3 mb-2">
              <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-[10px] font-black text-white">{googleUser?.name.charAt(0)}</div>
              <div className="min-w-0">
                <p className="text-[11px] font-black text-white truncate">{googleUser?.name}</p>
                <p className="text-[9px] text-[#1DB954] font-black uppercase">Linked</p>
              </div>
           </div>
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-[#0a0a0a] overflow-hidden relative">
        <header className="h-20 flex items-center justify-between px-10 border-b border-white/[0.03] backdrop-blur-md z-40">
          <div className="flex items-center gap-8 flex-1">
            <h2 className="text-sm font-black text-white uppercase tracking-widest italic flex-none">{activeTab.replace('-', ' ')}</h2>

            {activeTab === 'thinking-lab' && (
              <div className="max-w-md w-full relative group">
                <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-[#1DB954] transition-colors text-xs"></i>
                <input 
                  type="text"
                  placeholder="Search library by song or artist..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-white/[0.03] border border-white/5 rounded-full py-2.5 pl-11 pr-4 text-xs font-medium text-white placeholder-gray-600 focus:outline-none focus:ring-1 focus:ring-[#1DB954]/40 focus:bg-white/[0.06] transition-all"
                />
              </div>
            )}
          </div>

          <div className="flex items-center gap-6 ml-6 flex-none">
            <div className="flex items-center gap-2">
               <div className="w-2 h-2 rounded-full bg-[#1DB954] animate-pulse"></div>
               <span className="text-[10px] font-black uppercase tracking-widest text-[#1DB954]">Engine Live</span>
            </div>
            <i className="fas fa-cog text-gray-600 hover:text-white cursor-pointer transition-colors"></i>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {activeTab === 'thinking-lab' ? (
            <div className="animate-fade-in space-y-12">
               <div className="flex items-end justify-between mb-10">
                  <div className="max-w-xl">
                     <h2 className="text-4xl font-black tracking-tighter text-white mb-2 italic">Acoustic Manifold</h2>
                     <p className="text-gray-500 font-medium leading-relaxed">High-dimensional signal projection. Similar acoustic profiles are grouped in this latent dimension workspace.</p>
                  </div>
               </div>
               <div className="bg-white/[0.01] rounded-[3rem] border border-white/5 p-8 shadow-inner overflow-hidden">
                 <EmbeddingMap songs={library} selectedSongId={selectedSong?.id} onSelectSong={handleSelectSong} />
               </div>
               <div>
                  <h3 className="text-xl font-black text-white mb-8 italic uppercase tracking-tighter border-l-4 border-[#1DB954] pl-4">Synced Library {searchQuery && <span className="text-gray-500 font-normal ml-2">({filteredLibrary.length} results)</span>}</h3>
                  {filteredLibrary.length > 0 ? (
                    <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-5 gap-6">
                      {filteredLibrary.map(song => (
                        <div 
                          key={song.id} 
                          onClick={() => handleSelectSong(song)} 
                          className={`group p-6 rounded-[2.5rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center ${selectedSong?.id === song.id ? 'bg-[#1DB954]/10 ring-1 ring-[#1DB954]/30' : 'bg-white/[0.02] hover:bg-white/5'}`}
                        >
                          <div className="aspect-square w-full bg-black rounded-[2rem] mb-4 flex items-center justify-center shadow-lg group-hover:scale-105 transition-transform overflow-hidden relative">
                            <i className={`fas fa-compact-disc text-4xl transition-all duration-1000 ${selectedSong?.id === song.id ? 'text-[#1DB954] animate-spin-slow' : 'text-gray-800'}`}></i>
                          </div>
                          <h4 className="font-black text-xs truncate w-full text-white">{song.title}</h4>
                          <p className="text-[10px] text-gray-500 truncate w-full mt-1 font-bold uppercase">{song.artist}</p>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="py-20 flex flex-col items-center justify-center opacity-40">
                      <i className="fas fa-search text-5xl mb-4"></i>
                      <p className="text-sm font-black uppercase tracking-widest">No matching tracks found</p>
                    </div>
                  )}
               </div>
            </div>
          ) : (
            <div className="animate-fade-in max-w-5xl mx-auto space-y-12 pb-32">
               {/* Spotify Sync - Now contains the recommendation software */}
               <div className="flex flex-col md:flex-row gap-12 items-start">
                  <div className="flex-none w-full md:w-80 flex flex-col items-center bg-white/[0.02] p-8 rounded-[3rem] border border-white/5">
                     <SonicOrb energy={userProfile.preferenceVector.energy} brightness={userProfile.preferenceVector.spectralCentroid} intensity={userProfile.preferenceVector.mfccs} />
                     <div className="mt-8 text-center space-y-2">
                        <p className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-400">Synced Acoustic Identity</p>
                        <p className="text-xs text-gray-500 italic">Intensity: {Math.round(userProfile.preferenceVector.energy)}% • Rhythm: {Math.round(userProfile.preferenceVector.tempo)} BPM</p>
                     </div>
                  </div>
                  <div className="flex-1 space-y-10">
                     <section>
                        <h3 className="text-sm font-black mb-6 text-white uppercase tracking-widest flex items-center gap-3">
                           <i className="fas fa-microchip text-[#1DB954]"></i> Discovery Pipeline
                        </h3>
                        <div className="grid gap-4">
                           {loading ? (
                             Array(3).fill(0).map((_, i) => <div key={i} className="h-24 bg-white/5 rounded-3xl animate-pulse"></div>)
                           ) : recommendations.map(rec => (
                             <div key={rec.song.id} onClick={() => handleSelectSong(rec.song)} className="group bg-white/[0.02] hover:bg-white/[0.05] p-6 rounded-[2rem] border border-white/5 transition-all cursor-pointer flex items-center gap-6">
                                <div className="w-12 h-12 bg-black rounded-2xl flex items-center justify-center border border-white/5 group-hover:scale-110 transition-transform">
                                   <i className="fas fa-play text-[10px] text-[#1DB954]"></i>
                                </div>
                                <div className="flex-1 min-w-0">
                                   <div className="flex items-center gap-3 mb-1">
                                      <h4 className="font-black text-sm text-white truncate">{rec.song.title}</h4>
                                      <span className="text-[9px] font-black text-[#1DB954] uppercase tracking-tighter bg-[#1DB954]/10 px-2 py-0.5 rounded-full">{Math.round(rec.similarity * 100)}% Match</span>
                                   </div>
                                   <p className="text-[10px] text-gray-500 font-bold uppercase">{rec.song.artist}</p>
                                </div>
                                <div className="hidden lg:block max-w-[200px] text-[10px] text-gray-500 italic leading-snug">
                                   {rec.explanation}
                                </div>
                             </div>
                           ))}
                        </div>
                     </section>

                     <section>
                        <div className="flex items-center justify-between mb-6">
                           <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-3">
                              <i className="fas fa-globe text-indigo-400"></i> Global Discovery
                           </h3>
                           {isThinking && <div className="text-[10px] font-black text-indigo-400 animate-pulse uppercase tracking-widest">Processing...</div>}
                        </div>
                        <div className={`p-8 rounded-[3rem] border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/5 border-indigo-500/30' : 'bg-white/[0.01] border-white/5'}`}>
                           {searchLoading ? (
                             <div className="space-y-4">
                                <div className="h-4 w-3/4 bg-white/5 rounded animate-pulse"></div>
                                <div className="h-4 w-1/2 bg-white/5 rounded animate-pulse"></div>
                                <div className="h-20 bg-white/5 rounded-3xl animate-pulse"></div>
                             </div>
                           ) : liveDiscovery && (
                             <div className="animate-fade-in">
                                <div className="text-xs text-gray-400 leading-relaxed font-medium mb-8 bg-black/50 p-6 rounded-3xl border border-white/5 whitespace-pre-wrap">
                                   {liveDiscovery.text}
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                   {liveDiscovery.sources.map((src, idx) => (
                                     <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="px-5 py-4 bg-white/5 hover:bg-white/10 rounded-2xl text-[10px] text-gray-400 hover:text-white flex items-center justify-between border border-white/5 transition-all group">
                                       <span className="truncate pr-4">{src.title}</span>
                                       <i className="fas fa-external-link-alt text-[8px] opacity-30 group-hover:opacity-100 transition-opacity"></i>
                                     </a>
                                   ))}
                                </div>
                             </div>
                           )}
                        </div>
                     </section>
                  </div>
               </div>
            </div>
          )}
        </div>

        {/* FEEDBACK OVERLAY */}
        {showFeedback && (
          <div className="absolute bottom-28 left-1/2 -translate-x-1/2 w-full max-w-sm px-6 animate-slide-up z-50">
            <div className="bg-white p-10 rounded-[3rem] shadow-[0_50px_100px_rgba(0,0,0,0.8)] border border-white/10 flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-[#1DB954] rounded-2xl flex items-center justify-center mb-6 rotate-3 shadow-xl shadow-green-500/20">
                <i className="fas fa-brain text-black text-2xl"></i>
              </div>
              <p className="text-black font-black text-[10px] uppercase tracking-[0.4em] mb-3">Feedback Loop</p>
              <h4 className="text-gray-950 text-lg font-black mb-8 leading-tight tracking-tighter italic">Is this sonic match accurate?</h4>
              <div className="flex gap-4 w-full">
                <button onClick={() => submitFeedback(true)} className="flex-1 py-4 bg-black text-white text-[11px] font-black rounded-full hover:scale-105 transition-all">YES, PERFECT</button>
                <button onClick={() => submitFeedback(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 text-[11px] font-black rounded-full hover:bg-gray-200 transition-all">REFINE PATH</button>
              </div>
            </div>
          </div>
        )}

        <footer className="h-28 bg-black/90 border-t border-white/5 px-10 flex items-center justify-between z-40 backdrop-blur-xl">
           <div className="w-1/4 flex items-center gap-6">
              {selectedSong ? (
                 <div className="flex items-center gap-4 animate-fade-in">
                    <div className="w-16 h-16 bg-gray-900 rounded-2xl flex items-center justify-center border border-white/5">
                       <i className="fas fa-compact-disc text-[#1DB954] text-3xl animate-spin-slow"></i>
                    </div>
                    <div className="min-w-0">
                       <p className="text-sm font-black text-white truncate">{selectedSong.title}</p>
                       <p className="text-[10px] text-gray-500 font-bold uppercase truncate">{selectedSong.artist}</p>
                    </div>
                 </div>
              ) : <span className="text-[10px] text-gray-600 font-black uppercase tracking-widest italic opacity-40">Ready to Discover</span>}
           </div>

           <div className="w-1/2 flex flex-col items-center gap-3">
              <div className="flex items-center gap-10 text-gray-500">
                 <i className="fas fa-random text-sm hover:text-white cursor-pointer"></i>
                 <i className="fas fa-step-backward text-lg hover:text-white cursor-pointer"></i>
                 <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-black hover:scale-110 transition-transform cursor-pointer">
                    <i className="fas fa-play text-xl ml-1"></i>
                 </div>
                 <i className="fas fa-step-forward text-lg hover:text-white cursor-pointer"></i>
                 <i className="fas fa-redo text-sm hover:text-white cursor-pointer"></i>
              </div>
              <div className="w-full max-w-md h-1 bg-white/10 rounded-full relative overflow-hidden">
                 <div className="absolute inset-y-0 left-0 bg-white rounded-full" style={{ width: '45%' }}></div>
              </div>
           </div>

           <div className="w-1/4 flex justify-end items-center gap-6">
              <i className="fas fa-volume-up text-gray-500 text-sm"></i>
              <div className="w-24 h-1 bg-white/10 rounded-full relative">
                 <div className="absolute inset-y-0 left-0 bg-gray-400 rounded-full" style={{ width: '80%' }}></div>
              </div>
           </div>
        </footer>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .animate-spin-slow { animation: spin 15s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.6s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

type AuthStep = 'landing' | 'google-auth' | 'syncing' | 'authenticated';
type Tab = 'thinking-lab' | 'spotify-sync';

const App: React.FC = () => {
  const [authStep, setAuthStep] = useState<AuthStep>('landing');
  const [activeTab, setActiveTab] = useState<Tab>('thinking-lab');
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Auth State
  const [googleUser, setGoogleUser] = useState<{name: string, email: string} | null>(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  // Discovery State
  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);
  const [completedSongsCount, setCompletedSongsCount] = useState(0);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle feedback loop trigger: Wait 10s for completion.
  // Popup only appears after at least one song has been completed previously.
  useEffect(() => {
    if (selectedSong && authStep === 'authenticated') {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
      playbackTimerRef.current = setTimeout(() => {
        setCompletedSongsCount(prev => {
          const nextCount = prev + 1;
          // Gate the popup: Only show if we already have 1 or more completed tracks in history
          if (prev >= 1) {
            setShowFeedback(true);
          }
          return nextCount;
        });
      }, 10000); 
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, authStep]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, targetLibrary: Song[], isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...targetLibrary]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Synthesizing recommendation rationale...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 3);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, []);

  const handleStartGoogleAuth = () => {
    setAuthStep('google-auth');
  };

  const handleSelectGoogleAccount = (name: string, email: string) => {
    setIsAuthenticating(true);
    setGoogleUser({ name, email });
    setTimeout(() => {
      setIsAuthenticating(false);
      startSyncProcess(email);
    }, 1200);
  };

  const startSyncProcess = (email: string) => {
    setAuthStep('syncing');
    setIsImporting(true);
    setSyncLogs([
      `Authenticating ${email}...`,
      'Google SSO handshake verified.',
      'Fetching linked Spotify account permissions...',
      'Accessing "CloudExplorer_99" Spotify Library...'
    ]);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 800));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Found 12 high-match tracks in "Recent Discoveries" playlist.', 'Starting acoustic waveform decryption...']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Profiling: ${song.title}`);
        setSyncLogs(prev => [...prev, `[NEURAL] Mapping acoustic fingerprint for "${song.artist} - ${song.title}"...`]);
        setImportProgress(20 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 70));
        await new Promise(r => setTimeout(r, 150));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Manifold projection complete.', 'Spotify Library Synchronized.']);
      await new Promise(r => setTimeout(r, 600));

      setLibrary(IMPORTED_USER_LIBRARY);
      setIsImporting(false);
      setAuthStep('authenticated');
      setActiveTab('thinking-lab');

      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      const initialPref = firstSong.features;
      setUserProfile(prev => ({
        ...prev,
        preferenceVector: initialPref,
        history: [firstSong.id],
      }));

      updateRecommendations(initialPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    setShowFeedback(false); // Reset feedback if user manually changes song
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;
    setSearchLoading(true);
    setIsThinking(true);
    setActiveTab('spotify-sync'); // Recommendations are in Spotify Sync

    try {
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 20)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  const filteredLibrary = library.filter(song => 
    song.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    song.artist.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (authStep === 'landing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full text-center">
          <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center mb-10 shadow-[0_0_50px_rgba(29,185,84,0.1)] transform -rotate-3">
            <i className="fas fa-wave-square text-black text-5xl"></i>
          </div>
          <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
          <p className="text-gray-400 text-lg font-medium mb-10 leading-relaxed">
            The intelligent sonic laboratory. Sign in with Google to analyze your linked Spotify library and discover tracks through deep acoustic reasoning.
          </p>
          <button 
            onClick={handleStartGoogleAuth} 
            className="group w-full max-w-sm py-5 bg-white hover:bg-gray-100 text-gray-900 font-bold rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.05] active:scale-[0.98] shadow-2xl"
          >
            <img src="https://www.gstatic.com/images/branding/product/1x/googleg_48dp.png" alt="Google" className="w-8 h-8" />
            <span className="text-lg">Sign in with Google</span>
          </button>
        </div>
      </div>
    );
  }

  if (authStep === 'google-auth') {
    return (
      <div className="fixed inset-0 bg-[#f8f9fa] z-[100] flex items-center justify-center p-6">
        <div className="w-full max-w-[440px] bg-white rounded-lg shadow-xl p-10 border border-[#dadce0] animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <img src="https://www.gstatic.com/images/branding/googlelogo/1x/googlelogo_color_92x30dp.png" alt="Google" className="mb-6 w-24" />
            <h2 className="text-2xl font-normal text-[#202124] mb-2">Choose an account</h2>
            <p className="text-base text-[#202124] mb-8">to continue to <span className="font-medium">Musologist AI</span></p>
            {isAuthenticating ? (
              <div className="flex flex-col items-center py-10">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="mt-4 text-sm text-[#5f6368] font-medium">Connecting to Spotify Services...</p>
              </div>
            ) : (
              <div className="w-full border-t border-b border-[#dadce0] mb-8">
                <button 
                  onClick={() => handleSelectGoogleAccount('Alex Rivera', 'alex.rivera@gmail.com')}
                  className="w-full py-4 flex items-center gap-4 hover:bg-gray-50 transition-colors px-2 text-left group"
                >
                  <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white font-medium">A</div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#3c4043]">Alex Rivera</p>
                    <p className="text-xs text-[#5f6368]">alex.rivera@gmail.com</p>
                  </div>
                </button>
              </div>
            )}
            <p className="text-xs text-[#5f6368] text-left">
              Google will share your information with Musologist to link your Spotify playlist data securely.
            </p>
          </div>
        </div>
      </div>
    );
  }

  if (authStep === 'syncing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12 text-center">
        <div className="w-full max-w-2xl">
          <SonicOrb energy={70} brightness={85} intensity={90} />
          <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Extracting Spotify Genome'}</h2>
          <div className="w-full h-1.5 bg-white/5 rounded-full mt-8 overflow-hidden">
            <div className="h-full bg-[#1DB954] transition-all duration-300" style={{ width: `${importProgress}%` }}></div>
          </div>
          <div className="mt-12 h-40 overflow-hidden font-mono text-[10px] text-[#1DB954]/50 text-left space-y-2">
            {syncLogs.slice(-6).map((log, i) => <div key={i} className="animate-fade-in">>> {log}</div>)}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      {/* Sidebar Navigation */}
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-50">
        <div className="flex items-center gap-3 px-2 mb-4">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-2">
          <button 
            onClick={() => setActiveTab('thinking-lab')}
            className={`w-full flex items-center gap-4 py-3 px-4 rounded-xl font-black text-sm transition-all group ${activeTab === 'thinking-lab' ? 'bg-[#1DB954] text-black' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
          >
            <i className={`fas fa-brain transition-transform ${activeTab === 'thinking-lab' ? '' : 'group-hover:scale-110'}`}></i> Thinking Lab
          </button>
          <button 
            onClick={() => setActiveTab('spotify-sync')}
            className={`w-full flex items-center gap-4 py-3 px-4 rounded-xl font-black text-sm transition-all group ${activeTab === 'spotify-sync' ? 'bg-[#1DB954] text-black' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
          >
            <i className={`fas fa-sync-alt transition-transform ${activeTab === 'spotify-sync' ? 'rotate-180' : 'group-hover:rotate-180'}`}></i> Spotify Sync
          </button>
        </div>
        <div className="flex-1 border-t border-white/5 mt-4 pt-6 overflow-y-auto custom-scrollbar">
           <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4 px-4">Neural Clusters</p>
           {['Ethereal Ambient', 'Dynamic Funk', 'Melodic Soul', 'Sub-Bass Heavy'].map(cluster => (
             <div key={cluster} className="px-4 py-2 text-xs text-gray-500 hover:text-white cursor-pointer transition-colors flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-[#1DB954]/40"></span> {cluster}
             </div>
           ))}
        </div>
        <div className="p-4 bg-white/5 rounded-2xl border border-white/5">
           <div className="flex items-center gap-3 mb-2">
              <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-[10px] font-black text-white">{googleUser?.name.charAt(0)}</div>
              <div className="min-w-0">
                <p className="text-[11px] font-black text-white truncate">{googleUser?.name}</p>
                <p className="text-[9px] text-[#1DB954] font-black uppercase">Linked</p>
              </div>
           </div>
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-[#0a0a0a] overflow-hidden relative">
        <header className="h-20 flex items-center justify-between px-10 border-b border-white/[0.03] backdrop-blur-md z-40">
          <div className="flex items-center gap-8 flex-1">
            <h2 className="text-sm font-black text-white uppercase tracking-widest italic flex-none">{activeTab.replace('-', ' ')}</h2>

            {activeTab === 'thinking-lab' && (
              <div className="max-w-md w-full relative group">
                <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-[#1DB954] transition-colors text-xs"></i>
                <input 
                  type="text"
                  placeholder="Search library by song or artist..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-white/[0.03] border border-white/5 rounded-full py-2.5 pl-11 pr-4 text-xs font-medium text-white placeholder-gray-600 focus:outline-none focus:ring-1 focus:ring-[#1DB954]/40 focus:bg-white/[0.06] transition-all"
                />
              </div>
            )}
          </div>

          <div className="flex items-center gap-6 ml-6 flex-none">
            <div className="flex items-center gap-2">
               <div className="w-2 h-2 rounded-full bg-[#1DB954] animate-pulse"></div>
               <span className="text-[10px] font-black uppercase tracking-widest text-[#1DB954]">Engine Live</span>
            </div>
            <i className="fas fa-cog text-gray-600 hover:text-white cursor-pointer transition-colors"></i>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {activeTab === 'thinking-lab' ? (
            <div className="animate-fade-in space-y-12">
               <div className="flex items-end justify-between mb-10">
                  <div className="max-w-xl">
                     <h2 className="text-4xl font-black tracking-tighter text-white mb-2 italic">Acoustic Manifold</h2>
                     <p className="text-gray-500 font-medium leading-relaxed">High-dimensional signal projection. Similar acoustic profiles are grouped in this latent dimension workspace.</p>
                  </div>
               </div>
               <div className="bg-white/[0.01] rounded-[3rem] border border-white/5 p-8 shadow-inner overflow-hidden">
                 <EmbeddingMap songs={library} selectedSongId={selectedSong?.id} onSelectSong={handleSelectSong} />
               </div>
               <div>
                  <h3 className="text-xl font-black text-white mb-8 italic uppercase tracking-tighter border-l-4 border-[#1DB954] pl-4">Synced Library {searchQuery && <span className="text-gray-500 font-normal ml-2">({filteredLibrary.length} results)</span>}</h3>
                  {filteredLibrary.length > 0 ? (
                    <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-5 gap-6">
                      {filteredLibrary.map(song => (
                        <div 
                          key={song.id} 
                          onClick={() => handleSelectSong(song)} 
                          className={`group p-6 rounded-[2.5rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-center text-center ${selectedSong?.id === song.id ? 'bg-[#1DB954]/10 ring-1 ring-[#1DB954]/30' : 'bg-white/[0.02] hover:bg-white/5'}`}
                        >
                          <div className="aspect-square w-full bg-black rounded-[2rem] mb-4 flex items-center justify-center shadow-lg group-hover:scale-105 transition-transform overflow-hidden relative">
                            <i className={`fas fa-compact-disc text-4xl transition-all duration-1000 ${selectedSong?.id === song.id ? 'text-[#1DB954] animate-spin-slow' : 'text-gray-800'}`}></i>
                          </div>
                          <h4 className="font-black text-xs truncate w-full text-white">{song.title}</h4>
                          <p className="text-[10px] text-gray-500 truncate w-full mt-1 font-bold uppercase">{song.artist}</p>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="py-20 flex flex-col items-center justify-center opacity-40">
                      <i className="fas fa-search text-5xl mb-4"></i>
                      <p className="text-sm font-black uppercase tracking-widest">No matching tracks found</p>
                    </div>
                  )}
               </div>
            </div>
          ) : (
            <div className="animate-fade-in max-w-5xl mx-auto space-y-12 pb-32">
               {/* Spotify Sync - Now contains the recommendation software */}
               <div className="flex flex-col md:flex-row gap-12 items-start">
                  <div className="flex-none w-full md:w-80 flex flex-col items-center bg-white/[0.02] p-8 rounded-[3rem] border border-white/5">
                     <SonicOrb energy={userProfile.preferenceVector.energy} brightness={userProfile.preferenceVector.spectralCentroid} intensity={userProfile.preferenceVector.mfccs} />
                     <div className="mt-8 text-center space-y-2">
                        <p className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-400">Synced Acoustic Identity</p>
                        <p className="text-xs text-gray-500 italic">Intensity: {Math.round(userProfile.preferenceVector.energy)}% • Rhythm: {Math.round(userProfile.preferenceVector.tempo)} BPM</p>
                     </div>
                  </div>
                  <div className="flex-1 space-y-10">
                     <section>
                        <h3 className="text-sm font-black mb-6 text-white uppercase tracking-widest flex items-center gap-3">
                           <i className="fas fa-microchip text-[#1DB954]"></i> Discovery Pipeline
                        </h3>
                        <div className="grid gap-4">
                           {loading ? (
                             Array(3).fill(0).map((_, i) => <div key={i} className="h-24 bg-white/5 rounded-3xl animate-pulse"></div>)
                           ) : recommendations.map(rec => (
                             <div key={rec.song.id} onClick={() => handleSelectSong(rec.song)} className="group bg-white/[0.02] hover:bg-white/[0.05] p-6 rounded-[2rem] border border-white/5 transition-all cursor-pointer flex items-center gap-6">
                                <div className="w-12 h-12 bg-black rounded-2xl flex items-center justify-center border border-white/5 group-hover:scale-110 transition-transform">
                                   <i className="fas fa-play text-[10px] text-[#1DB954]"></i>
                                </div>
                                <div className="flex-1 min-w-0">
                                   <div className="flex items-center gap-3 mb-1">
                                      <h4 className="font-black text-sm text-white truncate">{rec.song.title}</h4>
                                      <span className="text-[9px] font-black text-[#1DB954] uppercase tracking-tighter bg-[#1DB954]/10 px-2 py-0.5 rounded-full">{Math.round(rec.similarity * 100)}% Match</span>
                                   </div>
                                   <p className="text-[10px] text-gray-500 font-bold uppercase">{rec.song.artist}</p>
                                </div>
                                <div className="hidden lg:block max-w-[200px] text-[10px] text-gray-500 italic leading-snug">
                                   {rec.explanation}
                                </div>
                             </div>
                           ))}
                        </div>
                     </section>

                     <section>
                        <div className="flex items-center justify-between mb-6">
                           <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-3">
                              <i className="fas fa-globe text-indigo-400"></i> Global Discovery
                           </h3>
                           {isThinking && <div className="text-[10px] font-black text-indigo-400 animate-pulse uppercase tracking-widest">Processing...</div>}
                        </div>
                        <div className={`p-8 rounded-[3rem] border transition-all duration-1000 ${isThinking ? 'bg-indigo-500/5 border-indigo-500/30' : 'bg-white/[0.01] border-white/5'}`}>
                           {searchLoading ? (
                             <div className="space-y-4">
                                <div className="h-4 w-3/4 bg-white/5 rounded animate-pulse"></div>
                                <div className="h-4 w-1/2 bg-white/5 rounded animate-pulse"></div>
                                <div className="h-20 bg-white/5 rounded-3xl animate-pulse"></div>
                             </div>
                           ) : liveDiscovery && (
                             <div className="animate-fade-in">
                                <div className="text-xs text-gray-400 leading-relaxed font-medium mb-8 bg-black/50 p-6 rounded-3xl border border-white/5 whitespace-pre-wrap">
                                   {liveDiscovery.text}
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                   {liveDiscovery.sources.map((src, idx) => (
                                     <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="px-5 py-4 bg-white/5 hover:bg-white/10 rounded-2xl text-[10px] text-gray-400 hover:text-white flex items-center justify-between border border-white/5 transition-all group">
                                       <span className="truncate pr-4">{src.title}</span>
                                       <i className="fas fa-external-link-alt text-[8px] opacity-30 group-hover:opacity-100 transition-opacity"></i>
                                     </a>
                                   ))}
                                </div>
                             </div>
                           )}
                        </div>
                     </section>
                  </div>
               </div>
            </div>
          )}
        </div>

        {/* FEEDBACK OVERLAY */}
        {showFeedback && (
          <div className="absolute bottom-28 left-1/2 -translate-x-1/2 w-full max-w-sm px-6 animate-slide-up z-50">
            <div className="bg-white p-10 rounded-[3rem] shadow-[0_50px_100px_rgba(0,0,0,0.8)] border border-white/10 flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-[#1DB954] rounded-2xl flex items-center justify-center mb-6 rotate-3 shadow-xl shadow-green-500/20">
                <i className="fas fa-brain text-black text-2xl"></i>
              </div>
              <p className="text-black font-black text-[10px] uppercase tracking-[0.4em] mb-3">Feedback Loop</p>
              <h4 className="text-gray-950 text-lg font-black mb-8 leading-tight tracking-tighter italic">Is this sonic match accurate?</h4>
              <div className="flex gap-4 w-full">
                <button onClick={() => submitFeedback(true)} className="flex-1 py-4 bg-black text-white text-[11px] font-black rounded-full hover:scale-105 transition-all">YES, PERFECT</button>
                <button onClick={() => submitFeedback(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 text-[11px] font-black rounded-full hover:bg-gray-200 transition-all">REFINE PATH</button>
              </div>
            </div>
          </div>
        )}

        <footer className="h-28 bg-black/90 border-t border-white/5 px-10 flex items-center justify-between z-40 backdrop-blur-xl">
           <div className="w-1/4 flex items-center gap-6">
              {selectedSong ? (
                 <div className="flex items-center gap-4 animate-fade-in">
                    <div className="w-16 h-16 bg-gray-900 rounded-2xl flex items-center justify-center border border-white/5">
                       <i className="fas fa-compact-disc text-[#1DB954] text-3xl animate-spin-slow"></i>
                    </div>
                    <div className="min-w-0">
                       <p className="text-sm font-black text-white truncate">{selectedSong.title}</p>
                       <p className="text-[10px] text-gray-500 font-bold uppercase truncate">{selectedSong.artist}</p>
                    </div>
                 </div>
              ) : <span className="text-[10px] text-gray-600 font-black uppercase tracking-widest italic opacity-40">Ready to Discover</span>}
           </div>

           <div className="w-1/2 flex flex-col items-center gap-3">
              <div className="flex items-center gap-10 text-gray-500">
                 <i className="fas fa-random text-sm hover:text-white cursor-pointer"></i>
                 <i className="fas fa-step-backward text-lg hover:text-white cursor-pointer"></i>
                 <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-black hover:scale-110 transition-transform cursor-pointer">
                    <i className="fas fa-play text-xl ml-1"></i>
                 </div>
                 <i className="fas fa-step-forward text-lg hover:text-white cursor-pointer"></i>
                 <i className="fas fa-redo text-sm hover:text-white cursor-pointer"></i>
              </div>
              <div className="w-full max-w-md h-1 bg-white/10 rounded-full relative overflow-hidden">
                 <div className="absolute inset-y-0 left-0 bg-white rounded-full" style={{ width: '45%' }}></div>
              </div>
           </div>

           <div className="w-1/4 flex justify-end items-center gap-6">
              <i className="fas fa-volume-up text-gray-500 text-sm"></i>
              <div className="w-24 h-1 bg-white/10 rounded-full relative">
                 <div className="absolute inset-y-0 left-0 bg-gray-400 rounded-full" style={{ width: '80%' }}></div>
              </div>
           </div>
        </footer>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .animate-spin-slow { animation: spin 15s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform: translate(-50%, 150%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.6s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in { animation: fadeIn 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MOCK_LIBRARY, IMPORTED_USER_LIBRARY } from './constants';
import { Song, UserProfile, Recommendation, AudioFeatures, LiveDiscovery } from './types';
import EmbeddingMap from './components/EmbeddingMap';
import SonicOrb from './components/SonicOrb';
import { getMusicalExplanation, getLiveDiscovery, getComplexRefinement } from './services/geminiService';

type AuthStep = 'landing' | 'google-auth' | 'syncing' | 'authenticated';
type Tab = 'thinking-lab' | 'spotify-sync';

const App: React.FC = () => {
  const [authStep, setAuthStep] = useState<AuthStep>('landing');
  const [activeTab, setActiveTab] = useState<Tab>('thinking-lab');
  const [library, setLibrary] = useState<Song[]>(MOCK_LIBRARY);
  const [selectedSong, setSelectedSong] = useState<Song | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importStatus, setImportStatus] = useState('');
  const [syncLogs, setSyncLogs] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Auth State
  const [googleUser, setGoogleUser] = useState<{name: string, email: string} | null>(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  // Discovery State
  const [userProfile, setUserProfile] = useState<UserProfile>({
    preferenceVector: { mfccs: 50, spectralCentroid: 50, zcr: 50, chroma: 50, tempo: 120, energy: 50 },
    history: [],
    liked: [],
  });
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [liveDiscovery, setLiveDiscovery] = useState<LiveDiscovery | null>(null);
  const [loading, setLoading] = useState(false);
  const [searchLoading, setSearchLoading] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [showFeedback, setShowFeedback] = useState(false);
  const [completedSongsCount, setCompletedSongsCount] = useState(0);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const playbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [syncLogs]);

  // Handle feedback loop trigger: Wait 10s for completion.
  // Popup only appears after at least one song has been completed previously.
  useEffect(() => {
    if (selectedSong && authStep === 'authenticated') {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
      playbackTimerRef.current = setTimeout(() => {
        setCompletedSongsCount(prev => {
          const nextCount = prev + 1;
          // Gate the popup: Only show if we already have 1 or more completed tracks in history
          if (prev >= 1) {
            setShowFeedback(true);
          }
          return nextCount;
        });
      }, 10000); 
    }
    return () => {
      if (playbackTimerRef.current) clearTimeout(playbackTimerRef.current);
    };
  }, [selectedSong, authStep]);

  const calculateSimilarity = (f1: AudioFeatures, f2: AudioFeatures) => {
    const keys: (keyof AudioFeatures)[] = ['mfccs', 'spectralCentroid', 'zcr', 'chroma', 'energy'];
    let sumSquares = 0;
    keys.forEach(key => {
      sumSquares += Math.pow(f1[key] - f2[key], 2);
    });
    sumSquares += Math.pow((f1.tempo - f2.tempo) / 2, 2);
    return 1 / (1 + Math.sqrt(sumSquares));
  };

  const updateRecommendations = useCallback(async (currentPref: AudioFeatures, song: Song, targetLibrary: Song[], isRefining = false) => {
    setLoading(true);
    setSearchLoading(true);
    if (isRefining) setIsThinking(true);

    const sorted = [...targetLibrary]
      .filter(s => s.id !== song.id)
      .map(s => ({
        song: s,
        similarity: calculateSimilarity(s.features, currentPref),
        explanation: 'Synthesizing recommendation rationale...',
      }))
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 3);

    const withExplanations = await Promise.all(sorted.map(async (rec) => {
      const explanation = await getMusicalExplanation(rec.song, currentPref);
      return { ...rec, explanation };
    }));

    setRecommendations(withExplanations);
    setLoading(false);

    try {
      let discovery;
      if (isRefining) {
        discovery = await getComplexRefinement(song, currentPref, true); 
      } else {
        discovery = await getLiveDiscovery(song, currentPref);
      }
      setLiveDiscovery(discovery);
    } catch (err) {
      console.error(err);
    } finally {
      setSearchLoading(false);
      setIsThinking(false);
    }
  }, []);

  const handleStartGoogleAuth = () => {
    setAuthStep('google-auth');
  };

  const handleSelectGoogleAccount = (name: string, email: string) => {
    setIsAuthenticating(true);
    setGoogleUser({ name, email });
    setTimeout(() => {
      setIsAuthenticating(false);
      startSyncProcess(email);
    }, 1200);
  };

  const startSyncProcess = (email: string) => {
    setAuthStep('syncing');
    setIsImporting(true);
    setSyncLogs([
      `Authenticating ${email}...`,
      'Google SSO handshake verified.',
      'Fetching linked Spotify account permissions...',
      'Accessing "CloudExplorer_99" Spotify Library...'
    ]);

    const runSync = async () => {
      await new Promise(r => setTimeout(r, 800));
      setImportProgress(10);
      setSyncLogs(prev => [...prev, 'Found 12 high-match tracks in "Recent Discoveries" playlist.', 'Starting acoustic waveform decryption...']);

      for (let i = 0; i < IMPORTED_USER_LIBRARY.length; i++) {
        const song = IMPORTED_USER_LIBRARY[i];
        setImportStatus(`Profiling: ${song.title}`);
        setSyncLogs(prev => [...prev, `[NEURAL] Mapping acoustic fingerprint for "${song.artist} - ${song.title}"...`]);
        setImportProgress(20 + Math.floor((i / IMPORTED_USER_LIBRARY.length) * 70));
        await new Promise(r => setTimeout(r, 150));
      }

      setImportProgress(100);
      setSyncLogs(prev => [...prev, 'Manifold projection complete.', 'Spotify Library Synchronized.']);
      await new Promise(r => setTimeout(r, 600));

      setLibrary(IMPORTED_USER_LIBRARY);
      setIsImporting(false);
      setAuthStep('authenticated');
      setActiveTab('thinking-lab');

      const firstSong = IMPORTED_USER_LIBRARY[0];
      setSelectedSong(firstSong);

      const initialPref = firstSong.features;
      setUserProfile(prev => ({
        ...prev,
        preferenceVector: initialPref,
        history: [firstSong.id],
      }));

      updateRecommendations(initialPref, firstSong, IMPORTED_USER_LIBRARY);
    };
    runSync();
  };

  const handleSelectSong = (song: Song) => {
    setSelectedSong(song);
    setShowFeedback(false); 
    const alpha = 0.35;
    setUserProfile(prev => {
      const newPref: AudioFeatures = {
        mfccs: Math.round(prev.preferenceVector.mfccs * (1 - alpha) + song.features.mfccs * alpha),
        spectralCentroid: Math.round(prev.preferenceVector.spectralCentroid * (1 - alpha) + song.features.spectralCentroid * alpha),
        zcr: Math.round(prev.preferenceVector.zcr * (1 - alpha) + song.features.zcr * alpha),
        chroma: Math.round(prev.preferenceVector.chroma * (1 - alpha) + song.features.chroma * alpha),
        tempo: Math.round(prev.preferenceVector.tempo * (1 - alpha) + song.features.tempo * alpha),
        energy: Math.round(prev.preferenceVector.energy * (1 - alpha) + song.features.energy * alpha),
      };

      const updatedHistory = [song.id, ...prev.history.filter(id => id !== song.id)].slice(0, 10);
      updateRecommendations(newPref, song, library);

      return {
        ...prev,
        preferenceVector: newPref,
        history: updatedHistory,
      };
    });
  };

  const submitFeedback = async (satisfied: boolean) => {
    setShowFeedback(false);
    if (!selectedSong) return;
    setSearchLoading(true);
    setIsThinking(true);
    setActiveTab('thinking-lab'); // Feedback results always show in the Lab

    try {
      const discovery = await getComplexRefinement(selectedSong, userProfile.preferenceVector, satisfied);
      setLiveDiscovery(discovery);

      if (!satisfied) {
        setUserProfile(prev => ({
          ...prev,
          preferenceVector: {
            ...prev.preferenceVector,
            energy: Math.max(0, Math.min(100, prev.preferenceVector.energy + (Math.random() - 0.5) * 20)),
          }
        }));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
      setSearchLoading(false);
    }
  };

  const filteredLibrary = library.filter(song => 
    song.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    song.artist.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (authStep === 'landing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-6 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-tr from-[#1DB954]/10 via-black to-[#1DB954]/5 pointer-events-none"></div>
        <div className="relative z-10 flex flex-col items-center max-w-lg w-full text-center">
          <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center mb-10 shadow-[0_0_50px_rgba(29,185,84,0.1)] transform -rotate-3">
            <i className="fas fa-wave-square text-black text-5xl"></i>
          </div>
          <h1 className="text-6xl font-black text-white mb-4 tracking-tighter italic">Musologist</h1>
          <p className="text-gray-400 text-lg font-medium mb-10 leading-relaxed">
            The intelligent sonic laboratory. Sign in with Google to analyze your linked Spotify library and discover tracks through deep acoustic reasoning.
          </p>
          <button 
            onClick={handleStartGoogleAuth} 
            className="group w-full max-w-sm py-5 bg-white hover:bg-gray-100 text-gray-900 font-bold rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.05] active:scale-[0.98] shadow-2xl"
          >
            <img src="https://www.gstatic.com/images/branding/product/1x/googleg_48dp.png" alt="Google" className="w-8 h-8" />
            <span className="text-lg">Sign in with Google</span>
          </button>
        </div>
      </div>
    );
  }

  if (authStep === 'google-auth') {
    return (
      <div className="fixed inset-0 bg-[#f8f9fa] z-[100] flex items-center justify-center p-6">
        <div className="w-full max-w-[440px] bg-white rounded-lg shadow-xl p-10 border border-[#dadce0] animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <img src="https://www.gstatic.com/images/branding/googlelogo/1x/googlelogo_color_92x30dp.png" alt="Google" className="mb-6 w-24" />
            <h2 className="text-2xl font-normal text-[#202124] mb-2">Choose an account</h2>
            <p className="text-base text-[#202124] mb-8">to continue to <span className="font-medium">Musologist AI</span></p>
            {isAuthenticating ? (
              <div className="flex flex-col items-center py-10">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="mt-4 text-sm text-[#5f6368] font-medium">Connecting to Spotify Services...</p>
              </div>
            ) : (
              <div className="w-full border-t border-b border-[#dadce0] mb-8">
                <button 
                  onClick={() => handleSelectGoogleAccount('Alex Rivera', 'alex.rivera@gmail.com')}
                  className="w-full py-4 flex items-center gap-4 hover:bg-gray-50 transition-colors px-2 text-left group"
                >
                  <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center text-white font-medium">A</div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-[#3c4043]">Alex Rivera</p>
                    <p className="text-xs text-[#5f6368]">alex.rivera@gmail.com</p>
                  </div>
                </button>
              </div>
            )}
            <p className="text-xs text-[#5f6368] text-left">
              Google will share your information with Musologist to link your Spotify playlist data securely.
            </p>
          </div>
        </div>
      </div>
    );
  }

  if (authStep === 'syncing') {
    return (
      <div className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center p-12 text-center">
        <div className="w-full max-w-2xl">
          <SonicOrb energy={70} brightness={85} intensity={90} />
          <h2 className="text-3xl font-black text-white mt-10 tracking-tighter uppercase italic">{importStatus || 'Extracting Spotify Genome'}</h2>
          <div className="w-full h-1.5 bg-white/5 rounded-full mt-8 overflow-hidden">
            <div className="h-full bg-[#1DB954] transition-all duration-300" style={{ width: `${importProgress}%` }}></div>
          </div>
          <div className="mt-12 h-40 overflow-hidden font-mono text-[10px] text-[#1DB954]/50 text-left space-y-2">
            {syncLogs.slice(-6).map((log, i) => <div key={i} className="animate-fade-in">>> {log}</div>)}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-gray-200 overflow-hidden font-sans">
      {/* Sidebar Navigation */}
      <nav className="w-64 flex-none bg-black flex flex-col p-6 space-y-8 border-r border-white/5 z-50">
        <div className="flex items-center gap-3 px-2 mb-4">
          <i className="fas fa-wave-square text-[#1DB954] text-2xl"></i>
          <span className="text-xl font-black tracking-tighter italic text-white">Musologist</span>
        </div>
        <div className="space-y-2">
          <button 
            onClick={() => setActiveTab('thinking-lab')}
            className={`w-full flex items-center gap-4 py-3 px-4 rounded-xl font-black text-sm transition-all group ${activeTab === 'thinking-lab' ? 'bg-[#1DB954] text-black' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
          >
            <i className={`fas fa-brain transition-transform ${activeTab === 'thinking-lab' ? '' : 'group-hover:scale-110'}`}></i> Thinking Lab
          </button>
          <button 
            onClick={() => setActiveTab('spotify-sync')}
            className={`w-full flex items-center gap-4 py-3 px-4 rounded-xl font-black text-sm transition-all group ${activeTab === 'spotify-sync' ? 'bg-[#1DB954] text-black' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
          >
            <i className={`fas fa-sync-alt transition-transform ${activeTab === 'spotify-sync' ? 'rotate-180' : 'group-hover:rotate-180'}`}></i> Spotify Sync
          </button>
        </div>
        <div className="flex-1 border-t border-white/5 mt-4 pt-6 overflow-y-auto custom-scrollbar">
           <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest mb-4 px-4">Neural Clusters</p>
           {['Ethereal Ambient', 'Dynamic Funk', 'Melodic Soul', 'Sub-Bass Heavy'].map(cluster => (
             <div key={cluster} className="px-4 py-2 text-xs text-gray-500 hover:text-white cursor-pointer transition-colors flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-[#1DB954]/40"></span> {cluster}
             </div>
           ))}
        </div>
        <div className="p-4 bg-white/5 rounded-2xl border border-white/5">
           <div className="flex items-center gap-3 mb-2">
              <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-[10px] font-black text-white">{googleUser?.name.charAt(0)}</div>
              <div className="min-w-0">
                <p className="text-[11px] font-black text-white truncate">{googleUser?.name}</p>
                <p className="text-[9px] text-[#1DB954] font-black uppercase">Linked</p>
              </div>
           </div>
        </div>
      </nav>

