                             )}
                          </div>
                       </section>
                    </div>
                  </div>
               </div>
            </div>
          ) : (
            <div className="animate-fade-in space-y-12 pb-32">
               <div>
                  <div className="max-w-5xl mb-12 flex flex-col md:flex-row md:items-end md:justify-between gap-8">
                     <div className="max-w-xl">
                        <h2 className="text-4xl font-black tracking-tighter text-white mb-2 italic">Acoustic Reconstruction</h2>
                        <p className="text-gray-500 font-medium leading-relaxed">High-fidelity profile of your Spotify library. Neural fingerprints are extracted and verified during each synchronization cycle.</p>
                     </div>
                     <div className="grid grid-cols-2 gap-4 bg-white/[0.03] p-6 rounded-[2.5rem] border border-white/5 flex-none shadow-2xl backdrop-blur-sm">
                        <div className="space-y-1">
                           <p className="text-[9px] font-black uppercase text-[#1DB954] tracking-widest">Signal Integrity</p>
                           <p className="text-sm font-black text-white italic">Optimal (100%)</p>
                        </div>
                        <div className="space-y-1 text-right">
                           <p className="text-[9px] font-black uppercase text-gray-600 tracking-widest">Library Size</p>
                           <p className="text-sm font-black text-white italic">{library.length} Components</p>
                        </div>
                        <div className="col-span-2 pt-2 border-t border-white/5 flex items-center justify-between gap-6">
                           <div className="flex items-center gap-2 text-gray-500">
                              <i className="fas fa-history text-[10px]"></i>
                              <span className="text-[10px] font-bold">Updated: {lastSyncedAt || 'Never'}</span>
                           </div>
                           <button 
                             onClick={() => googleUser && startSyncProcess(googleUser.email)}
                             className="text-[9px] font-black uppercase text-white hover:text-[#1DB954] transition-colors flex items-center gap-2 group"
                           >
                              <i className="fas fa-sync-alt text-[8px] group-hover:rotate-180 transition-transform duration-500"></i> Refresh
