                  <div className="flex items-center justify-between mb-8">
                    <h3 className="text-xl font-black text-white italic uppercase tracking-tighter border-l-4 border-[#1DB954] pl-4">Extracted Collection {searchQuery && <span className="text-gray-500 font-normal ml-2">({filteredLibrary.length} results)</span>}</h3>
                    <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest text-gray-600">
