                  {filteredLibrary.length > 0 ? (
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6">
                      {filteredLibrary.map(song => (
                        <div 
                          key={song.id} 
                          onClick={() => handleSelectSong(song)} 
                          className={`group p-5 rounded-[2rem] transition-all cursor-pointer relative overflow-hidden flex flex-col items-start text-left ${selectedSong?.id === song.id ? 'bg-[#1DB954]/10 ring-1 ring-[#1DB954]/30' : 'bg-white/[0.02] hover:bg-white/5 shadow-xl'}`}
                        >
