            <div className="animate-fade-in space-y-12 pb-32">
               <ContentSearchBar />

               <div>
                  <div className="max-w-5xl mb-8 flex flex-col md:flex-row md:items-end md:justify-between gap-8">
                     <div className="max-w-xl">
                        <h2 className="text-4xl font-black tracking-tighter text-white mb-2 italic">Acoustic Reconstruction</h2>
                        <p className="text-gray-500 font-medium leading-relaxed">High-fidelity profile of your Spotify library. Artist metadata and cover art are retrieved during each sync.</p>
