                            {selectedSong?.id === song.id && <div className="absolute inset-0 bg-[#1DB954]/5 flex items-center justify-center backdrop-blur-[1px]"><div className="w-3 h-3 rounded-full bg-[#1DB954] animate-ping"></div></div>}
