          results.push({ type: 'artist', value: s.artist, id: `a-${s.artist}` });
        }
      }
      if (s.title.toLowerCase().includes(query)) {
        results.push({ type: 'song', value: `${s.title} - ${s.artist}`, id: `s-${s.id}` });
