              className="group w-full py-5 bg-[#1DB954] hover:bg-[#1ed760] text-black font-black rounded-full flex items-center justify-center gap-4 transition-all transform hover:scale-[1.05] active:scale-[0.98] shadow-[0_15px_40px_rgba(29,185,84,0.2)]"
            >
              <i className="fab fa-spotify text-2xl"></i>
              <span className="text-lg">Connect Spotify</span>
            </button>
            <button 
