import { GoogleGenAI, Type } from "@google/genai";
import { AudioFeatures, Song, LiveDiscovery, SearchSource, Recommendation } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Batched explanation service to save quota and avoid 429 errors.
 * Fetches explanations for multiple songs in a single request.
 */
export const getBatchedMusicalExplanations = async (songs: Song[], userPref: AudioFeatures): Promise<string[]> => {
  const songsList = songs.map((s, i) => `${i + 1}. "${s.title}" by ${s.artist} (Energy: ${s.features.energy}, BPM: ${s.features.tempo})`).join('\n');

  const prompt = `
    Acts as an intuitive music discovery AI. Explain why these tracks match a user's current "vibe" based on acoustic patterns.

    CRITICAL: DO NOT mention technical terms like MFCC, Spectral Centroid, ZCR, or Chroma. 

    Target Tracks:
    ${songsList}

    User Vibe: ${userPref.energy > 60 ? 'Energetic & Vibrant' : 'Mellow & Atmospheric'}

    Return a JSON array of strings, one short natural sentence for each track in order.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const text = response.text;
    if (text) {
      return JSON.parse(text);
    }
    return songs.map(() => "This track aligns with your recent acoustic signature.");
  } catch (error: any) {
    // Graceful handling of 429 Resource Exhausted
    if (error?.message?.includes('429')) {
      console.warn("Gemini Quota Reached. Using fallback explanations.");
    } else {
      console.error("Gemini Error:", error);
    }
    return songs.map(() => "Synthesizing your sonic DNA...");
  }
};

/**
 * Explains musical matches using the standard flash model for low latency.
 * @deprecated Use getBatchedMusicalExplanations instead to avoid 429s.
 */
export const getMusicalExplanation = async (song: Song, userPref: AudioFeatures): Promise<string> => {
  try {
    const results = await getBatchedMusicalExplanations([song], userPref);
    return results[0];
  } catch {
    return "This track perfectly complements your sound patterns.";
  }
};

/**
 * Standard search grounding for discovery.
 */
export const getLiveDiscovery = async (song: Song, userPref: AudioFeatures): Promise<LiveDiscovery> => {
  const prompt = `
    Search for 3-4 real-world songs released in 2024 or 2025 that share a similar sonic profile with "${song.title}" by ${song.artist}.
    Focus on Energy: ${song.features.energy}, Tempo: ${song.features.tempo}.
    Format as markdown list.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    return processSearchResponse(response);
  } catch (error: any) {
    if (error?.message?.includes('429')) {
      console.warn("Search Quota Reached.");
    } else {
      console.error("Live Discovery Error:", error);
    }
    return { text: "Sonic mapping temporarily paused due to high demand.", sources: [] };
  }
};

